// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
// before claim in the work / work paths. The hook evaluates the bead
// using the repository's triage prompt and returns one of the typed intake
// outcomes so the loop can decide whether to claim or skip the candidate.
//
// The hook uses the normal service execution path. Unpinned workers use the
// warmed lifecycle profile snapshot when available; explicitly pinned workers
// keep their operator route pins. Route failures are infrastructure failures, not
// bead-readiness decisions, so they return intake_error and let the loop use
// its fail-open readiness path.
func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
	return NewPreClaimIntakeHookWithLog(projectRoot, store, rcfg, svc, runner, nil)
}

// NewPreClaimIntakeHookWithLog constructs the pre-claim intake hook and emits
// compact prompt metadata plus live service progress to log when provided.
func NewPreClaimIntakeHookWithLog(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner, log io.Writer) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
	return NewPreClaimIntakeHookWithLogVerbose(projectRoot, store, rcfg, svc, runner, log, false)
}

// NewPreClaimIntakeHookWithLogVerbose constructs the pre-claim intake hook and
// prints the full prompt only when promptVerbose is true.
func NewPreClaimIntakeHookWithLogVerbose(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner, log io.Writer, promptVerbose bool) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
	return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return PreClaimIntakeResult{}, err
			}
		}
		if strings.TrimSpace(projectRoot) == "" {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
		}
		if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: %w", err)
		}
		if store == nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
		}

		b, err := store.Get(beadID)
		if err != nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
		}

		prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
		if err != nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
		}

		runtime := AgentRunRuntime{
			Prompt:        prompt,
			PromptSource:  PreClaimIntakePromptSource,
			Output:        log,
			WorkLogPhase:  "readiness",
			Correlation:   map[string]string{"bead_id": beadID},
			ClearProfile:  true,
			ClearMinPower: true,
		}
		runtime.ClearMaxPower = true
		logPreClaimIntakePrompt(log, projectRoot, beadID, prompt, runtime, promptVerbose)
		applyLifecycleHookRouting(ctx, projectRoot, svc, runner, rcfg, &runtime, SelectStandardProfile)
		logPreClaimIntakeRoute(log, beadID, runtime, promptVerbose)
		payload, err := dispatchPreClaimIntakePayload(ctx, projectRoot, svc, runner, rcfg, runtime)
		if err != nil {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeError,
				Detail:  preClaimIntakeRouteUnavailableDetail(err),
			}, nil
		}

		return decodePreClaimIntakePayloadResultWithMode(payload, rcfg.BeadQualityMode())
	}
}

func logPreClaimIntakePrompt(w io.Writer, projectRoot, beadID, prompt string, runtime AgentRunRuntime, verbose bool) {
	if w == nil || !verbose {
		return
	}
	logDir := ResolveLogDir(projectRoot, "")
	_, _ = fmt.Fprintf(w, "readiness prompt %s: sent source=%s bytes=%d session_logs=%s\n", beadID, PreClaimIntakePromptSource, len(prompt), logDir)
	_, _ = fmt.Fprintf(w, "readiness prompt %s begin\n%s", beadID, truncatePreClaimIntakePromptForLog(prompt))
	if !strings.HasSuffix(prompt, "\n") {
		_, _ = fmt.Fprintln(w)
	}
	_, _ = fmt.Fprintf(w, "readiness prompt %s end\n", beadID)
}

func logPreClaimIntakeRoute(w io.Writer, beadID string, runtime AgentRunRuntime, verbose bool) {
	if w == nil || !verbose {
		return
	}
	if route := preClaimIntakeRouteSummary(runtime); route != "" {
		_, _ = fmt.Fprintf(w, "readiness prompt %s: route %s\n", beadID, route)
	}
}

func preClaimIntakeRouteSummary(runtime AgentRunRuntime) string {
	var fields []string
	if runtime.ProfileOverride != "" {
		fields = append(fields, "profile="+runtime.ProfileOverride)
	}
	if runtime.HarnessOverride != "" {
		fields = append(fields, "harness="+runtime.HarnessOverride)
	}
	if runtime.ProviderOverride != "" {
		fields = append(fields, "provider="+runtime.ProviderOverride)
	}
	if runtime.ModelOverride != "" {
		fields = append(fields, "model="+runtime.ModelOverride)
	}
	return strings.Join(fields, " ")
}

func truncatePreClaimIntakePromptForLog(prompt string) string {
	const limit = 32 * 1024
	if len(prompt) <= limit {
		return prompt
	}
	const marker = "\n...[readiness prompt truncated in worker log; full prompt is in the service session log]...\n"
	head := (limit - len(marker)) / 2
	tail := limit - len(marker) - head
	if head <= 0 || tail <= 0 {
		return prompt[:limit]
	}
	return prompt[:head] + marker + prompt[len(prompt)-tail:]
}

func applyLifecycleHookRouting(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime *AgentRunRuntime, selector func(ProfileSnapshot) string) {
	runtime.ClearRoutingPins = true

	pinned := false
	if harness, ok := rcfg.ExplicitHarness(); ok {
		runtime.HarnessOverride = strings.TrimSpace(harness)
		pinned = true
	}
	if provider, ok := rcfg.ExplicitProvider(); ok {
		runtime.ProviderOverride = strings.TrimSpace(provider)
		pinned = true
	}
	if model, ok := rcfg.ExplicitModel(); ok {
		runtime.ModelOverride = strings.TrimSpace(model)
		pinned = true
	}
	if pinned {
		return
	}
	runtime.ProfileOverride = selectProfileForDispatch(ctx, projectRoot, svc, runner, selector)
}

func dispatchPreClaimIntakePayload(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (string, error) {
	return dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
}

func preClaimIntakeRouteUnavailableDetail(err error) string {
	detail := ""
	if err != nil {
		detail = strings.TrimSpace(err.Error())
	}
	detail = trimDiagnosticPrefix(detail, "pre-claim intake")
	detail = strings.TrimPrefix(strings.TrimSpace(detail), "dispatch: ")
	if detail == "" {
		return "readiness route unavailable"
	}
	return "readiness route unavailable: " + detail
}

func dispatchPreClaimIntakePayloadOnce(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (string, error) {
	result, err := dispatchLifecycleRun(ctx, projectRoot, svc, runner, rcfg, runtime)
	if err != nil {
		return "", fmt.Errorf("pre-claim intake: dispatch: %w", err)
	}
	return intakeResultPayload(result)
}

func buildPreClaimIntakePrompt(projectRoot string, store BeadReader, b *bead.Bead) (string, error) {
	env := preClaimIntakePromptEnvelope{
		Title:         strings.TrimSpace(b.Title),
		Description:   strings.TrimSpace(b.Description),
		Acceptance:    strings.TrimSpace(b.Acceptance),
		Labels:        append([]string(nil), b.Labels...),
		PriorAttempts: []preClaimIntakeAttempt{},
		Depth:         beadDecompositionDepth(projectRoot, b),
		Parent:        strings.TrimSpace(b.Parent),
		Dependencies:  append([]string(nil), b.DepIDs()...),
	}

	// Prior attempts are optional for the gate. If bead history is available,
	// include the last few attempt/result summaries to help the classifier
	// distinguish a first-pass atomic bead from repeated decomposition.
	if store != nil {
		if eventStore, ok := any(store).(interface {
			Events(id string) ([]bead.BeadEvent, error)
		}); ok {
			if events, err := eventStore.Events(b.ID); err == nil && len(events) > 0 {
				for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
					ev := events[i]
					if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
						continue
					}
					env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
						Status:    strings.TrimSpace(ev.Summary),
						Rationale: strings.TrimSpace(ev.Body),
					})
				}
			}
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", err
	}

	var sb strings.Builder
	sb.WriteString("MODE: intake\n")
	sb.WriteString("You are evaluating whether this bead is atomic, decomposable, ambiguous, or safely refinable before claim.\n")
	sb.WriteString("Do not rewrite bead fields in intake mode. If the bead is executable as written, classify it as ready even when the prose could be cleaner.\n")
	sb.WriteString("Return exactly one JSON object matching the readiness schema with classification, tractability, score, rationale, difficulty, readiness_checks, suggested_fixes, rewrite, suggested_child_beads, and waivers_applied.\n")
	sb.WriteString("readiness_checks MUST be a JSON array; it may be empty, and every entry MUST be an object with reason, verdict, evidence, and checkable_before_attempt. It must not be an object or string.\n")
	sb.WriteString("suggested_fixes MUST be a JSON array; use a flat string list for prompt-quality suggestions, or an empty array when none apply.\n")
	sb.WriteString("suggested_child_beads MUST be a JSON array of objects. When a child includes acceptance, prefer a JSON string array of numbered criteria; the decoder tolerates a single string fallback, but do not rely on it.\n")
	sb.WriteString("waivers_applied MUST be a JSON array. Prefer waiver objects with reason, criteria, and evidence; the decoder tolerates a flat string list fallback, but do not rely on it.\n")
	sb.WriteString("difficulty MUST be an object with estimated_difficulty and reason. estimated_difficulty MUST be exactly one of easy, medium, or hard.\n")
	sb.WriteString("Use medium as the default implementation difficulty when uncertain or when the task is ordinary build/test/code work; medium maps to standard dispatch.\n")
	sb.WriteString("Use easy only for work suitable for cheap dispatch: narrow mechanical edits such as typo fixes, formatting, simple docs/prose tweaks, straightforward fixture updates, or one-file transforms with low blast radius.\n")
	sb.WriteString("Use hard only for work suitable for smart dispatch: architecture or ambiguous tradeoff judgment, multiple subsystems with high blast radius, security/data-loss/concurrency risk, or prior attempts showing standard power is insufficient.\n")
	sb.WriteString("Do not choose hard just because a bead is important, long, or could be written more cleanly. Readiness score and difficulty are separate: low readiness means refine/split/block, not hard.\n")
	sb.WriteString("If the bead is not executable as written but can be made executable by a narrow, semantics-preserving metadata/AC rewrite, emit rewrite with changed_fields, description, and acceptance.\n")
	sb.WriteString("Put prompt-quality improvements in suggested_fixes only; keep operator_required for actual blockers.\n")
	sb.WriteString("Preservation rules: non-scope items, governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, and dependency IDs (ddx-XXXXXXXX) must all appear in the replacement description.\n")
	sb.WriteString("Classify as operator_required only when ambiguity, missing prerequisites, hidden external blockers, or unsafe scope choices prevent an implementation attempt.\n")
	sb.WriteString("Do not include prose or markdown.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func intakeResultPayload(result *Result) (string, error) {
	if result == nil {
		return "", fmt.Errorf("pre-claim intake: empty runner result")
	}
	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		if strings.TrimSpace(result.Error) != "" {
			return "", fmt.Errorf("pre-claim intake: runner error: %s", strings.TrimSpace(result.Error))
		}
		if result.ExitCode != 0 {
			return "", fmt.Errorf("pre-claim intake: runner exited with code %d and empty output", result.ExitCode)
		}
		return "", fmt.Errorf("pre-claim intake: empty output")
	}
	candidate, ok := extractJSONCandidate(text)
	if !ok {
		return "", fmt.Errorf("pre-claim intake: no JSON object found")
	}
	return candidate, nil
}

func normalizePreClaimIntakeRewriteFields(fields []string) []string {
	if len(fields) == 0 {
		return nil
	}
	seen := make(map[string]struct{}, len(fields))
	out := make([]string, 0, len(fields))
	for _, field := range fields {
		field = strings.ToLower(strings.TrimSpace(field))
		if field == "" {
			continue
		}
		if _, ok := seen[field]; ok {
			continue
		}
		seen[field] = struct{}{}
		out = append(out, field)
	}
	return out
}

// decodePreClaimIntakePayloadResult decodes a JSON payload into a PreClaimIntakeResult.
// It accepts both the legacy intake schema (classification field) and the canonical
// readiness schema (outcome field), converting both into the same decision model.
func decodePreClaimIntakePayloadResult(payload string) (PreClaimIntakeResult, error) {
	return decodePreClaimIntakePayloadResultWithMode(payload, config.BeadQualityModeWarnOnly)
}

func decodePreClaimIntakePayloadResultWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
	var probe struct {
		Classification  string                                 `json:"classification"`
		Outcome         string                                 `json:"outcome"`
		Tractability    string                                 `json:"tractability"`
		Rationale       string                                 `json:"rationale"`
		Score           preClaimReadinessScore                 `json:"score"`
		Difficulty      preClaimReadinessDifficulty            `json:"difficulty"`
		ReadinessChecks preClaimReadinessChecksPayload         `json:"readiness_checks"`
		SuggestedFixes  preClaimReadinessSuggestedFixesPayload `json:"suggested_fixes"`
	}
	if err := json.Unmarshal([]byte(payload), &probe); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
	}
	if probe.Outcome != "" {
		return decodeCanonicalReadinessPayloadWithMode(payload, qualityMode)
	}
	if probe.Classification != "" {
		if isReadinessClassificationPayload(probe.Classification, probe.Tractability, probe.Rationale, probe.Score.Present, normalizeReadinessEstimatedDifficulty(probe.Difficulty.EstimatedDifficulty) != "", probe.ReadinessChecks.Present, probe.ReadinessChecks.Len(), len(probe.SuggestedFixes)) {
			return decodeReadinessClassificationPayloadWithMode(payload, qualityMode)
		}
		return decodeLegacyIntakePayload(payload)
	}
	return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
}

func isReadinessClassificationPayload(classification, tractability, rationale string, scorePresent, difficultyPresent bool, readinessChecksPresent bool, checkCount, fixCount int) bool {
	switch strings.ToLower(strings.TrimSpace(classification)) {
	case ReadinessClassificationSystemUnready,
		"readiness_error",
		"intake_error",
		ReadinessClassificationNeedsRefine,
		ReadinessClassificationNeedsSplit,
		ReadinessClassificationOperatorRequired,
		"ambiguous",
		"safely_refinable",
		"split":
		return true
	case "ready":
		return readinessChecksPresent ||
			strings.TrimSpace(tractability) != "" ||
			strings.TrimSpace(rationale) != "" ||
			scorePresent ||
			difficultyPresent ||
			checkCount > 0 ||
			fixCount > 0
	default:
		return false
	}
}

func decodeCanonicalReadinessPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
	var out preClaimReadinessPromptResult
	if err := json.Unmarshal([]byte(payload), &out); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
	}
	detail := strings.TrimSpace(out.Reason)
	if detail == "" {
		detail = strings.TrimSpace(out.Detail)
	}
	rewrite := PreClaimIntakeRewrite{
		Description:   strings.TrimSpace(out.Rewrite.Description),
		Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
		ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
	}
	estimatedDifficulty := normalizeReadinessEstimatedDifficulty(out.Difficulty.EstimatedDifficulty)
	switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
	case "actionable_atomic":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail, EstimatedDifficulty: estimatedDifficulty}, nil
	case "actionable_but_rewritten":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, EstimatedDifficulty: estimatedDifficulty, Rewrite: rewrite}, nil
	case "too_large_decomposed":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Reason: ReadinessReasonTooLarge, Detail: detail, EstimatedDifficulty: estimatedDifficulty}, nil
	case "operator_required", "human_review_required":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeOperatorRequired, Reason: ReadinessReasonAmbiguousScope, Detail: detail, EstimatedDifficulty: estimatedDifficulty}, nil
	case "ambiguous_needs_human", "needs_human":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy readiness outcome %q removed by lifecycle migration; use %q", out.Outcome, PreClaimIntakeOperatorRequired)
	case "readiness_error", "system_unready":
		// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
		classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
		return PreClaimIntakeResult{
			Outcome:      PreClaimIntakeError,
			Reason:       classified.Reason,
			SystemReason: classified.SystemReason,
			Detail:       detail,
		}, nil
	case "":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
	default:
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, operator_required, readiness_error, system_unready", out.Outcome)
	}
}

func decodeReadinessClassificationPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
	var out preClaimReadinessClassificationPromptResult
	if err := json.Unmarshal([]byte(payload), &out); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness classification result: %w", err)
	}
	if out.ReadinessChecks.Malformed != "" {
		detail := malformedReadinessChecksDetail(out.ReadinessChecks)
		classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
		return PreClaimIntakeResult{
			Outcome:      classified.IntakeOutcome,
			Reason:       classified.Reason,
			SystemReason: classified.SystemReason,
			Detail:       detail,
		}, nil
	}
	reasons := failedReadinessReasons(out.ReadinessChecks.Checks)
	detail := firstNonEmptyReadinessDetail(out.Rationale, out.Detail, out.Reasoning)
	classified := ClassifyReadinessWithMode(out.Classification, reasons, detail, qualityMode)
	if detail == "" {
		detail = readinessCheckEvidence(out.ReadinessChecks.Checks)
	}
	detail = readinessDetailWithReason(classified, detail)

	rewrite := PreClaimIntakeRewrite{
		Description:   strings.TrimSpace(out.Rewrite.Description),
		Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
		ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
	}
	result := PreClaimIntakeResult{
		Outcome:             classified.IntakeOutcome,
		Reason:              classified.Reason,
		SystemReason:        classified.SystemReason,
		Detail:              detail,
		EstimatedDifficulty: normalizeReadinessEstimatedDifficulty(out.Difficulty.EstimatedDifficulty),
	}
	if classified.Classification == ReadinessClassificationNeedsRefine && hasPreClaimIntakeRewrite(rewrite) {
		result.Outcome = PreClaimIntakeActionableButRewritten
		result.Rewrite = rewrite
	}
	return result, nil
}

func failedReadinessReasons(checks []preClaimReadinessCheck) []string {
	reasons := make([]string, 0, len(checks))
	for _, check := range checks {
		verdict := strings.ToLower(strings.TrimSpace(check.Verdict))
		if verdict != "fail" {
			continue
		}
		if reason := strings.TrimSpace(check.Reason); reason != "" {
			reasons = append(reasons, reason)
		}
	}
	return reasons
}

func malformedReadinessChecksDetail(checks preClaimReadinessChecksPayload) string {
	detail := strings.TrimSpace(checks.Malformed)
	if detail == "" {
		detail = "readiness_checks must be an object or array"
	}
	if evidence := strings.TrimSpace(checks.Evidence); evidence != "" {
		detail += ": " + strconv.Quote(evidence)
	}
	return detail
}

func readinessCheckEvidence(checks []preClaimReadinessCheck) string {
	for _, check := range checks {
		if strings.ToLower(strings.TrimSpace(check.Verdict)) != "fail" {
			continue
		}
		if evidence := strings.TrimSpace(check.Evidence); evidence != "" {
			return evidence
		}
	}
	return ""
}

func readinessDetailWithReason(classified ReadinessClassificationResult, detail string) string {
	detail = strings.TrimSpace(detail)
	reason := strings.TrimSpace(classified.Reason)
	if reason == "" {
		return detail
	}
	if detail == "" {
		return reason
	}
	if strings.Contains(strings.ToLower(detail), strings.ToLower(reason)) {
		return detail
	}
	return reason + ": " + detail
}

func firstNonEmptyReadinessDetail(values ...string) string {
	for _, value := range values {
		if trimmed := strings.TrimSpace(value); trimmed != "" {
			return trimmed
		}
	}
	return ""
}

func hasPreClaimIntakeRewrite(rewrite PreClaimIntakeRewrite) bool {
	return strings.TrimSpace(rewrite.Description) != "" ||
		strings.TrimSpace(rewrite.Acceptance) != "" ||
		len(rewrite.ChangedFields) > 0
}

func normalizeReadinessEstimatedDifficulty(raw string) string {
	switch strings.ToLower(strings.TrimSpace(raw)) {
	case string(escalation.DifficultyEasy):
		return string(escalation.DifficultyEasy)
	case string(escalation.DifficultyMedium):
		return string(escalation.DifficultyMedium)
	case string(escalation.DifficultyHard):
		return string(escalation.DifficultyHard)
	default:
		return ""
	}
}

func resolveReadinessEstimatedDifficulty(b *bead.Bead, readinessEstimate string) escalation.EstimatedDifficulty {
	if difficulty, ok := escalation.BeadEstimatedDifficulty(b); ok {
		return difficulty
	}
	switch normalizeReadinessEstimatedDifficulty(readinessEstimate) {
	case string(escalation.DifficultyEasy):
		return escalation.DifficultyEasy
	case string(escalation.DifficultyHard):
		return escalation.DifficultyHard
	default:
		return escalation.DifficultyMedium
	}
}

func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
	var out preClaimIntakePromptResult
	if err := json.Unmarshal([]byte(payload), &out); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
	}
	switch strings.ToLower(strings.TrimSpace(out.Classification)) {
	case "atomic", "ok", "ready", "actionable", "pass":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
	case "rewritten":
		return PreClaimIntakeResult{
			Outcome: PreClaimIntakeActionableButRewritten,
			Detail:  strings.TrimSpace(out.Reasoning),
			Rewrite: PreClaimIntakeRewrite{
				Description:   strings.TrimSpace(out.Rewrite.Description),
				Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
				ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
			},
		}, nil
	case "decomposable":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
	case "ambiguous", "ambiguous_scope", "needs_human", "ambiguous_needs_human":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy classification %q removed by lifecycle migration; use outcome %q", out.Classification, PreClaimIntakeOperatorRequired)
	case "":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
	default:
		return PreClaimIntakeResult{}, fmt.Errorf(
			"pre-claim intake: unknown classification %q: expected one of ready, needs_refine, needs_split, operator_required, system_unready",
			out.Classification,
		)
	}
}

package agent

import (
	"context"
	"fmt"
	"math"
	"path/filepath"
	"reflect"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	agentlib "github.com/easel/fizeau"
)

const (
	profileSnapshotCacheWindow       = 5 * time.Minute
	profileSnapshotRefreshInterval   = 30 * time.Second
	profileSnapshotRefreshTimeout    = 15 * time.Second
	profileSnapshotColdLoadTimeout   = 2 * time.Second
	profileSnapshotRefreshRetryAfter = 5 * time.Second
)

var (
	profileSnapshotCacheMu     sync.Mutex
	profileSnapshotCache       = map[string]profileSnapshotCacheEntry{}
	profileSnapshotNow         = time.Now
	profileSnapshotLoadTimeout = 3 * time.Second
)

type profileSnapshotCacheEntry struct {
	snap             ProfileSnapshot
	loadedAt         time.Time
	refreshing       bool
	refreshStartedAt time.Time
	lastAttemptAt    time.Time
}

// ProfileSnapshot is the fizeau-owned routing vocabulary DDx uses for hidden
// lifecycle dispatches. DDx selects policy names from this snapshot; it does
// not resolve concrete models.
type ProfileSnapshot struct {
	Profiles []agentlib.PolicyInfo
	Models   []agentlib.ModelInfo
}

type ImplementationProfileSelection struct {
	Name     string
	MinPower int
	Degraded bool
	Note     string
}

// LoadProfileSnapshot fetches fizeau profiles and models with short-lived,
// stale-on-error memoization keyed to the service identity.
func LoadProfileSnapshot(ctx context.Context, svc agentlib.FizeauService) (ProfileSnapshot, error) {
	if svc == nil {
		return ProfileSnapshot{}, nil
	}
	if ctx == nil {
		ctx = context.Background()
	}
	key := profileSnapshotServiceCacheKey(svc)
	return loadProfileSnapshot(ctx, key, svc)
}

// WarmProfileSnapshotForProject starts a non-blocking refresh of the profile
// snapshot used by lifecycle hooks. It is intentionally best-effort; callers
// should proceed without a DDx-selected profile when no hot snapshot is present.
func WarmProfileSnapshotForProject(projectRoot string, svc agentlib.FizeauService, runner AgentRunner) {
	if runner != nil {
		return
	}
	selectedSvc := svc
	if selectedSvc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(projectRoot)
		if err != nil {
			return
		}
		selectedSvc = built
	}
	startProfileSnapshotRefresh(profileSnapshotProjectCacheKey(projectRoot, selectedSvc), selectedSvc)
}

func loadProfileSnapshot(ctx context.Context, key string, svc agentlib.FizeauService) (ProfileSnapshot, error) {
	now := profileSnapshotNow()

	var last profileSnapshotCacheEntry
	var hadLast bool
	if key != "" {
		profileSnapshotCacheMu.Lock()
		if entry, ok := profileSnapshotCache[key]; ok && now.Sub(entry.loadedAt) < profileSnapshotCacheWindow {
			snap := cloneProfileSnapshot(entry.snap)
			profileSnapshotCacheMu.Unlock()
			return snap, nil
		}
		last, hadLast = profileSnapshotCache[key]
		profileSnapshotCacheMu.Unlock()
	}

	loadCtx, cancel := context.WithTimeout(ctx, profileSnapshotLoadTimeout)
	defer cancel()

	profiles, err := svc.ListPolicies(loadCtx)
	if err != nil {
		if hadLast {
			markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
			return cloneProfileSnapshot(last.snap), nil
		}
		markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
		return ProfileSnapshot{}, err
	}
	models, err := svc.ListModels(loadCtx, agentlib.ModelFilter{})
	if err != nil {
		if hadLast {
			markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
			return cloneProfileSnapshot(last.snap), nil
		}
		// Model discovery is advisory for DDx profile selection. Fizeau still
		// owns concrete routing and candidate filtering at dispatch time, so do
		// not let a slow/stale model snapshot consume the readiness budget.
		models = nil
	}

	snap := ProfileSnapshot{
		Profiles: append([]agentlib.PolicyInfo(nil), profiles...),
		Models:   append([]agentlib.ModelInfo(nil), models...),
	}
	if key != "" {
		profileSnapshotCacheMu.Lock()
		profileSnapshotCache[key] = profileSnapshotCacheEntry{snap: cloneProfileSnapshot(snap), loadedAt: now}
		profileSnapshotCacheMu.Unlock()
	}
	return snap, nil
}

func cachedProfileSnapshot(key string) (ProfileSnapshot, bool) {
	if key == "" {
		return ProfileSnapshot{}, false
	}
	profileSnapshotCacheMu.Lock()
	defer profileSnapshotCacheMu.Unlock()
	entry, ok := profileSnapshotCache[key]
	if !ok || len(entry.snap.Profiles) == 0 {
		return ProfileSnapshot{}, false
	}
	return cloneProfileSnapshot(entry.snap), true
}

func startProfileSnapshotRefresh(key string, svc agentlib.FizeauService) {
	if key == "" || svc == nil {
		return
	}
	now := profileSnapshotNow()
	profileSnapshotCacheMu.Lock()
	entry := profileSnapshotCache[key]
	if entry.refreshing && now.Sub(entry.refreshStartedAt) < profileSnapshotRefreshTimeout {
		profileSnapshotCacheMu.Unlock()
		return
	}
	if !entry.loadedAt.IsZero() && now.Sub(entry.loadedAt) < profileSnapshotRefreshInterval {
		profileSnapshotCacheMu.Unlock()
		return
	}
	if !entry.lastAttemptAt.IsZero() && now.Sub(entry.lastAttemptAt) < profileSnapshotRefreshRetryAfter {
		profileSnapshotCacheMu.Unlock()
		return
	}
	entry.refreshing = true
	entry.refreshStartedAt = now
	entry.lastAttemptAt = now
	profileSnapshotCache[key] = entry
	profileSnapshotCacheMu.Unlock()

	go func() {
		ctx, cancel := context.WithTimeout(context.Background(), profileSnapshotRefreshTimeout)
		defer cancel()
		snap, err := fetchProfileSnapshot(ctx, svc)
		if err != nil {
			markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
			return
		}
		markProfileSnapshotRefreshDone(key, true, snap)
	}()
}

func fetchProfileSnapshot(ctx context.Context, svc agentlib.FizeauService) (ProfileSnapshot, error) {
	profiles, err := svc.ListPolicies(ctx)
	if err != nil {
		return ProfileSnapshot{}, err
	}
	return ProfileSnapshot{
		Profiles: append([]agentlib.PolicyInfo(nil), profiles...),
	}, nil
}

func markProfileSnapshotRefreshDone(key string, ok bool, snap ProfileSnapshot) {
	if key == "" {
		return
	}
	now := profileSnapshotNow()
	profileSnapshotCacheMu.Lock()
	entry := profileSnapshotCache[key]
	entry.refreshing = false
	if ok {
		entry.snap = cloneProfileSnapshot(snap)
		entry.loadedAt = now
	}
	profileSnapshotCache[key] = entry
	profileSnapshotCacheMu.Unlock()
}

func profileSnapshotProjectCacheKey(projectRoot string, svc agentlib.FizeauService) string {
	if root := strings.TrimSpace(projectRoot); root != "" {
		return "project:" + filepath.Clean(root)
	}
	return profileSnapshotServiceCacheKey(svc)
}

func profileSnapshotServiceCacheKey(svc agentlib.FizeauService) string {
	t := reflect.TypeOf(svc)
	if t == nil {
		return ""
	}
	v := reflect.ValueOf(svc)
	switch v.Kind() {
	case reflect.Chan, reflect.Func, reflect.Map, reflect.Pointer, reflect.Slice, reflect.UnsafePointer:
		if v.IsNil() {
			return ""
		}
		return fmt.Sprintf("service:%s:%x", t.String(), v.Pointer())
	default:
		if t.Comparable() {
			return fmt.Sprintf("service:%s:%v", t.String(), svc)
		}
	}
	return ""
}

func cloneProfileSnapshot(snap ProfileSnapshot) ProfileSnapshot {
	return ProfileSnapshot{
		Profiles: append([]agentlib.PolicyInfo(nil), snap.Profiles...),
		Models:   append([]agentlib.ModelInfo(nil), snap.Models...),
	}
}

// SelectCheapestProfile returns the lowest-power profile band that has at least
// one available, auto-routable model.
func SelectCheapestProfile(snap ProfileSnapshot) string {
	profiles := satisfiableProfiles(snap, 0)
	sort.SliceStable(profiles, func(i, j int) bool {
		left, right := profiles[i], profiles[j]
		if profileMaxForSort(left) != profileMaxForSort(right) {
			return profileMaxForSort(left) < profileMaxForSort(right)
		}
		if left.MinPower != right.MinPower {
			return left.MinPower < right.MinPower
		}
		return preferProfile(left, right)
	})
	if len(profiles) == 0 {
		return ""
	}
	return profiles[0].Name
}

// SelectStrongestProfile returns the highest-power profile band that has at
// least one available, auto-routable model.
func SelectStrongestProfile(snap ProfileSnapshot) string {
	profiles := satisfiableProfiles(snap, 0)
	sort.SliceStable(profiles, func(i, j int) bool {
		left, right := profiles[i], profiles[j]
		if left.MinPower != right.MinPower {
			return left.MinPower > right.MinPower
		}
		if profileMaxForSort(left) != profileMaxForSort(right) {
			return profileMaxForSort(left) > profileMaxForSort(right)
		}
		return preferProfile(left, right)
	})
	if len(profiles) == 0 {
		return ""
	}
	return profiles[0].Name
}

// SelectStrongestProfileAbove returns the strongest satisfiable profile whose
// lower bound is at least floor.
func SelectStrongestProfileAbove(snap ProfileSnapshot, floor int) string {
	profiles := satisfiableProfiles(snap, floor)
	sort.SliceStable(profiles, func(i, j int) bool {
		left, right := profiles[i], profiles[j]
		if left.MinPower != right.MinPower {
			return left.MinPower > right.MinPower
		}
		if profileMaxForSort(left) != profileMaxForSort(right) {
			return profileMaxForSort(left) > profileMaxForSort(right)
		}
		return preferProfile(left, right)
	})
	if len(profiles) == 0 {
		return ""
	}
	return profiles[0].Name
}

// SelectStandardProfile returns the ordinary implementation policy band. It is
// used for lifecycle checks that need competent judgment but should not consume
// top-tier routing unless there is explicit evidence to escalate.
func SelectStandardProfile(snap ProfileSnapshot) string {
	return SelectImplementationProfile(snap, escalation.PowerStandard).Name
}

// SelectImplementationProfile chooses an opaque Fizeau profile name for
// implementation work. It ranks by policy metadata, not by hard-coded policy
// names. Ordinary auto-routing avoids profiles with hard requirements (for
// example local-only/no-remote policy requirements) unless DDx has an explicit
// matching intent; explicit --profile remains a raw passthrough handled by
// Fizeau.
func SelectImplementationProfile(snap ProfileSnapshot, powerClass escalation.PowerClass) ImplementationProfileSelection {
	return selectImplementationProfile(snap, powerClass, 0)
}

// SelectImplementationProfileForMinPower chooses an implementation profile
// whose advertised power range can satisfy the requested lower bound. It is
// used by retry escalation so DDx does not keep a weak profile pinned after it
// has raised MinPower beyond that profile's range.
func SelectImplementationProfileForMinPower(snap ProfileSnapshot, powerClass escalation.PowerClass, floor int) ImplementationProfileSelection {
	return selectImplementationProfile(snap, powerClass, floor)
}

func selectImplementationProfile(snap ProfileSnapshot, powerClass escalation.PowerClass, floor int) ImplementationProfileSelection {
	profiles := implementationCandidateProfiles(snap, floor)
	if len(profiles) == 0 {
		return ImplementationProfileSelection{}
	}
	selected, note := chooseImplementationCandidate(snap, profiles, powerClass, floor)
	return ImplementationProfileSelection{
		Name:     selected.Name,
		MinPower: selected.MinPower,
		Degraded: note != "",
		Note:     note,
	}
}

func implementationCandidateProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
	profiles := satisfiableProfiles(snap, 0)
	out := make([]agentlib.PolicyInfo, 0, len(profiles))
	for _, profile := range profiles {
		if hasHardPolicyRequirement(profile) {
			continue
		}
		if floor > 0 && profileMaxForSort(profile) < floor {
			continue
		}
		out = append(out, profile)
	}
	sort.SliceStable(out, func(i, j int) bool {
		return implementationProfileLess(snap, out[i], out[j])
	})
	return out
}

func chooseImplementationCandidate(snap ProfileSnapshot, profiles []agentlib.PolicyInfo, powerClass escalation.PowerClass, floor int) (agentlib.PolicyInfo, string) {
	if floor > 0 && powerClass != escalation.PowerSmart {
		return profiles[0], ""
	}
	switch powerClass {
	case escalation.PowerSmart:
		return profiles[len(profiles)-1], ""
	case escalation.PowerStandard:
		if selected, note, ok := standardProfileSelection(snap, profiles); ok {
			return selected, note
		}
		return profiles[0], "medium profile unavailable; using only available profile"
	case escalation.PowerCheap, "":
		return profiles[0], ""
	default:
		return profiles[0], ""
	}
}

func firstBandAboveLowest(profiles []agentlib.PolicyInfo) (agentlib.PolicyInfo, bool) {
	if len(profiles) <= 1 {
		return agentlib.PolicyInfo{}, false
	}
	lowest := profiles[0]
	for _, profile := range profiles[1:] {
		if profile.MinPower > lowest.MinPower || profileMaxForSort(profile) > profileMaxForSort(lowest) {
			return profile, true
		}
	}
	return agentlib.PolicyInfo{}, false
}

// standardProfileSelection prefers the configured medium band. Model discovery
// is advisory and may be stale relative to Fizeau's live route resolver, so a
// standard-powerClass implementation must not silently downgrade to the weakest
// policy just because the cached model snapshot does not currently contain a
// live medium-band candidate.
func standardProfileSelection(snap ProfileSnapshot, available []agentlib.PolicyInfo) (agentlib.PolicyInfo, string, bool) {
	if len(available) == 0 {
		return agentlib.PolicyInfo{}, "", false
	}
	desired, ok := desiredStandardProfile(snap)
	if !ok {
		if selected, ok := firstBandAboveLowest(available); ok {
			return selected, "", true
		}
		return agentlib.PolicyInfo{}, "", false
	}
	for _, profile := range available {
		if profile.Name == desired.Name {
			return profile, "", true
		}
	}
	return desired, "medium profile absent from live model snapshot; requesting medium policy", true
}

func desiredStandardProfile(snap ProfileSnapshot) (agentlib.PolicyInfo, bool) {
	profiles := make([]agentlib.PolicyInfo, 0, len(snap.Profiles))
	for _, profile := range snap.Profiles {
		if profile.Name == "" || hasHardPolicyRequirement(profile) {
			continue
		}
		if profile.MinPower == 0 && profile.MaxPower == 0 {
			continue
		}
		profiles = append(profiles, profile)
	}
	sort.SliceStable(profiles, func(i, j int) bool {
		if profileMaxForSort(profiles[i]) != profileMaxForSort(profiles[j]) {
			return profileMaxForSort(profiles[i]) < profileMaxForSort(profiles[j])
		}
		if profiles[i].MinPower != profiles[j].MinPower {
			return profiles[i].MinPower < profiles[j].MinPower
		}
		return profiles[i].Name < profiles[j].Name
	})
	return firstBandAboveLowest(profiles)
}

func hasHardPolicyRequirement(profile agentlib.PolicyInfo) bool {
	for _, requirement := range profile.Require {
		if strings.TrimSpace(requirement) != "" {
			return true
		}
	}
	return false
}

func satisfiableProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
	out := make([]agentlib.PolicyInfo, 0, len(snap.Profiles))
	for _, profile := range snap.Profiles {
		if profile.Name == "" {
			continue
		}
		if hasHardPolicyRequirement(profile) {
			continue
		}
		if profile.MinPower == 0 && profile.MaxPower == 0 {
			continue
		}
		if floor > 0 && profile.MinPower < floor {
			continue
		}
		if profileHasAvailableModel(profile, snap.Models) {
			out = append(out, profile)
		}
	}
	return out
}

func profileHasAvailableModel(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) bool {
	if len(models) == 0 {
		return true
	}
	for _, model := range models {
		if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
			continue
		}
		if profile.MinPower > 0 && model.Power < profile.MinPower {
			continue
		}
		if profile.MaxPower > 0 && model.Power > profile.MaxPower {
			continue
		}
		return true
	}
	return false
}

func implementationProfileLess(snap ProfileSnapshot, left, right agentlib.PolicyInfo) bool {
	if profileMaxForSort(left) != profileMaxForSort(right) {
		return profileMaxForSort(left) < profileMaxForSort(right)
	}
	if left.MinPower != right.MinPower {
		return left.MinPower < right.MinPower
	}
	leftCost, leftCostOK := profileBestCost(left, snap.Models)
	rightCost, rightCostOK := profileBestCost(right, snap.Models)
	if leftCostOK != rightCostOK {
		return leftCostOK
	}
	if leftCostOK && rightCostOK && leftCost != rightCost {
		return leftCost < rightCost
	}
	leftSpeed, leftSpeedOK := profileBestSpeed(left, snap.Models)
	rightSpeed, rightSpeedOK := profileBestSpeed(right, snap.Models)
	if leftSpeedOK != rightSpeedOK {
		return leftSpeedOK
	}
	if leftSpeedOK && rightSpeedOK && leftSpeed != rightSpeed {
		return leftSpeed > rightSpeed
	}
	return left.Name < right.Name
}

func profileBestCost(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) (float64, bool) {
	best := 0.0
	ok := false
	for _, model := range models {
		if !modelFitsProfile(profile, model) {
			continue
		}
		cost := model.Cost.InputPerMTok + model.Cost.OutputPerMTok
		if !ok || cost < best {
			best = cost
			ok = true
		}
	}
	return best, ok
}

func profileBestSpeed(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) (float64, bool) {
	best := 0.0
	ok := false
	for _, model := range models {
		if !modelFitsProfile(profile, model) {
			continue
		}
		speed := model.PerfSignal.SpeedTokensPerSec
		if speed <= 0 {
			continue
		}
		if !ok || speed > best {
			best = speed
			ok = true
		}
	}
	return best, ok
}

func modelFitsProfile(profile agentlib.PolicyInfo, model agentlib.ModelInfo) bool {
	if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
		return false
	}
	if profile.MinPower > 0 && model.Power < profile.MinPower {
		return false
	}
	if profile.MaxPower > 0 && model.Power > profile.MaxPower {
		return false
	}
	return true
}

func profileMaxForSort(profile agentlib.PolicyInfo) int {
	if profile.MaxPower == 0 {
		return math.MaxInt
	}
	return profile.MaxPower
}

func preferProfile(left, right agentlib.PolicyInfo) bool {
	return left.Name < right.Name
}

func selectProfileForDispatch(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, selector func(ProfileSnapshot) string) string {
	if selector == nil || runner != nil {
		return ""
	}
	blocking := svc != nil
	selectedSvc := svc
	if selectedSvc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(projectRoot)
		if err != nil {
			return ""
		}
		selectedSvc = built
	}
	key := profileSnapshotProjectCacheKey(projectRoot, selectedSvc)
	if snap, ok := cachedProfileSnapshot(key); ok {
		startProfileSnapshotRefresh(key, selectedSvc)
		return selector(snap)
	}
	if blocking {
		snap, err := loadProfileSnapshot(ctx, key, selectedSvc)
		if err != nil {
			return ""
		}
		return selector(snap)
	}
	if coldCtx, cancel := profileSnapshotColdLoadContext(ctx); coldCtx != nil {
		defer cancel()
		snap, err := loadProfilePolicySnapshot(coldCtx, key, selectedSvc)
		if err == nil {
			startProfileSnapshotRefresh(key, selectedSvc)
			return selector(snap)
		}
	}
	startProfileSnapshotRefresh(key, selectedSvc)
	return ""
}

func loadProfilePolicySnapshot(ctx context.Context, key string, svc agentlib.FizeauService) (ProfileSnapshot, error) {
	profiles, err := svc.ListPolicies(ctx)
	if err != nil {
		return ProfileSnapshot{}, err
	}
	snap := ProfileSnapshot{Profiles: append([]agentlib.PolicyInfo(nil), profiles...)}
	if key != "" {
		profileSnapshotCacheMu.Lock()
		profileSnapshotCache[key] = profileSnapshotCacheEntry{snap: cloneProfileSnapshot(snap), loadedAt: profileSnapshotNow()}
		profileSnapshotCacheMu.Unlock()
	}
	return snap, nil
}

func profileSnapshotColdLoadContext(parent context.Context) (context.Context, context.CancelFunc) {
	if profileSnapshotColdLoadTimeout <= 0 {
		if parent == nil {
			return context.Background(), func() {}
		}
		return parent, func() {}
	}
	if parent == nil {
		parent = context.Background()
	}
	return context.WithTimeout(parent, profileSnapshotColdLoadTimeout)
}

package agent

import (
	"context"
	"net/http"
	"strconv"
	"strings"
	"time"

	agentlib "github.com/easel/fizeau"
)

// RateLimitRetryDefaultBudget is the default per-bead total wait budget for
// rate-limit retries. AC #4 of ddx-c6e3db02 names 5 minutes.
const RateLimitRetryDefaultBudget = 5 * time.Minute

// RateLimitRetryDefaultPerWaitCap caps any single retry wait so a misbehaving
// provider cannot pin the worker with a one-hour Retry-After. The bead
// description names 60 seconds as the per-wait cap.
const RateLimitRetryDefaultPerWaitCap = 60 * time.Second

// RateLimitBudgetExhaustedReason is the canonical reason string written into
// Result.Error when the per-bead retry budget is exhausted. The execute-bead
// status mapping translates this into FailureModeAuthError so it surfaces in
// the standard execution_failed pathway (TD-031 §8.4).
const RateLimitBudgetExhaustedReason = "rate-limited beyond budget"

// RateLimitRetryEventKind is the bead event kind appended on each retry per
// TD-031 §4 / §8.4 RateLimitRetryContract. The body carries the retry count
// and wait duration.
const RateLimitRetryEventKind = "rate-limit-retry"

// rateLimitBackoffSchedule is the exponential-backoff fallback when a 429
// response carries no parseable Retry-After value. The schedule names the
// wait for the 1st, 2nd, … retry; entries past the end repeat the last value.
// AC #3 of ddx-c6e3db02 specifies 1s, 5s, 15s, 30s, 60s.
var rateLimitBackoffSchedule = []time.Duration{
	1 * time.Second,
	5 * time.Second,
	15 * time.Second,
	30 * time.Second,
	60 * time.Second,
}

// RateLimitWaitDecision is the policy output for one rate-limit response.
// The policy never mutates state; the caller decides whether to wait + retry
// or to give up and surface RateLimitBudgetExhaustedReason.
type RateLimitWaitDecision struct {
	// ShouldRetry is true when the budget allows another wait + retry.
	ShouldRetry bool
	// Wait is the duration the caller should sleep before retrying.
	// Only meaningful when ShouldRetry is true.
	Wait time.Duration
	// Source classifies how Wait was derived: "retry-after" when the upstream
	// response named a specific delay, "exponential-backoff" when the schedule
	// fallback was used. Empty when ShouldRetry is false.
	Source string
	// Reason is populated when ShouldRetry is false; carries
	// RateLimitBudgetExhaustedReason in the budget-exhausted case.
	Reason string
}

// EvaluateRateLimitWait decides how long to wait before retrying after a
// rate-limit response, and whether the per-bead budget allows the retry.
//
// retryAfter is the duration parsed from the response (zero when absent /
// unparseable). attempt is 1-indexed (first retry = 1). elapsed is the total
// wait already spent on this bead. budget is the total cap (zero = unbounded,
// disabling budget enforcement). perWaitCap caps any single wait (zero =
// uncapped).
//
// The function is pure: no I/O, no time.Now, no global state.
func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
	if budget > 0 && elapsed >= budget {
		return RateLimitWaitDecision{
			ShouldRetry: false,
			Reason:      RateLimitBudgetExhaustedReason,
		}
	}

	var wait time.Duration
	var source string
	if retryAfter > 0 {
		wait = retryAfter
		source = "retry-after"
	} else {
		idx := attempt - 1
		if idx < 0 {
			idx = 0
		}
		if idx >= len(rateLimitBackoffSchedule) {
			idx = len(rateLimitBackoffSchedule) - 1
		}
		wait = rateLimitBackoffSchedule[idx]
		source = "exponential-backoff"
	}

	if perWaitCap > 0 && wait > perWaitCap {
		wait = perWaitCap
	}

	if budget > 0 && elapsed+wait > budget {
		// Trim the final wait so the bead doesn't block beyond the budget.
		// If trimming leaves nothing, treat the budget as exhausted.
		remaining := budget - elapsed
		if remaining <= 0 {
			return RateLimitWaitDecision{
				ShouldRetry: false,
				Reason:      RateLimitBudgetExhaustedReason,
			}
		}
		wait = remaining
	}

	return RateLimitWaitDecision{
		ShouldRetry: true,
		Wait:        wait,
		Source:      source,
	}
}

// IsRateLimitResult reports whether a Runner Result indicates a rate-limit
// (HTTP 429) event that the per-bead retry policy should handle.
//
// Quota exhaustion (NoViableProviderForNow) is OUT of scope for
// RateLimitRetryContract per ddx-c6e3db02 AC #8 — it belongs to
// QuotaPauseContract (ddx-aede917d). The detection here matches the canonical
// 429 / "rate limit" / "ratelimit" markers without matching "quota exceeded".
func IsRateLimitResult(result *Result) bool {
	if result == nil {
		return false
	}
	combined := strings.ToLower(result.Error + "\n" + result.Stderr)
	if combined == "\n" {
		return false
	}
	// Quota wording must NOT match: that path is QuotaPauseContract
	// (ddx-aede917d), not RateLimitRetryContract.
	if strings.Contains(combined, "quota exceeded") ||
		strings.Contains(combined, "insufficient quota") ||
		strings.Contains(combined, "no viable provider") {
		return false
	}
	if strings.Contains(combined, "rate limit") ||
		strings.Contains(combined, "ratelimit") {
		return true
	}
	// Match HTTP 429 with word boundary around the digits — avoid matching
	// "port 4290" or fragment timestamps. The conservative form is to look
	// for "429" framed by non-digits or as an HTTP status marker.
	if hasIsolated429(combined) {
		return true
	}
	return false
}

// hasIsolated429 returns true when the input contains "429" framed so it
// cannot be a substring of a longer number (e.g. "4290", "12429"). A simple
// scan is enough — the haystack is short.
func hasIsolated429(s string) bool {
	for i := 0; i+3 <= len(s); i++ {
		if s[i:i+3] != "429" {
			continue
		}
		// Check left boundary.
		if i > 0 {
			c := s[i-1]
			if c >= '0' && c <= '9' {
				continue
			}
		}
		// Check right boundary.
		if i+3 < len(s) {
			c := s[i+3]
			if c >= '0' && c <= '9' {
				continue
			}
		}
		return true
	}
	return false
}

// ParseRetryAfter parses a Retry-After header value per RFC 7231 §7.1.3:
// either a non-negative integer ("delta-seconds") or an HTTP-date.
// Returns zero duration when the value is empty or unparseable.
//
// now is supplied so tests can pin the clock; production callers pass
// time.Now().
func ParseRetryAfter(value string, now time.Time) time.Duration {
	value = strings.TrimSpace(value)
	if value == "" {
		return 0
	}
	if secs, err := strconv.Atoi(value); err == nil {
		if secs < 0 {
			return 0
		}
		return time.Duration(secs) * time.Second
	}
	// HTTP-date: RFC 1123 / 850 / asctime per http.ParseTime.
	if t, err := http.ParseTime(value); err == nil {
		d := t.Sub(now)
		if d < 0 {
			return 0
		}
		return d
	}
	// Last resort: a Go duration literal ("30s", "2m"). Some harnesses emit
	// this style on stderr; treat it as a courtesy.
	if d, err := time.ParseDuration(value); err == nil && d >= 0 {
		return d
	}
	return 0
}

// ExtractRetryAfterFromStderr scans subprocess stderr for a Retry-After
// indication and returns the parsed wait. Returns zero when no indication is
// present so the caller falls back to exponential backoff.
//
// Recognised forms (case-insensitive):
//   - "Retry-After: <value>" (HTTP header echoed by the harness)
//   - "retry_after=<value>" (structured key=value form some harnesses emit)
//   - "retry after <value>"
//
// now is used as the reference for HTTP-date values.
func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
	if stderr == "" {
		return 0
	}
	lower := strings.ToLower(stderr)
	for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
		idx := strings.Index(lower, marker)
		if idx < 0 {
			continue
		}
		rest := stderr[idx+len(marker):]
		// Read up to the end of the line.
		if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
			rest = rest[:eol]
		}
		// Strip surrounding quotes/spaces and an optional comma terminator.
		rest = strings.TrimSpace(rest)
		rest = strings.Trim(rest, "\"',")
		if d := ParseRetryAfter(rest, now); d > 0 {
			return d
		}
	}
	return 0
}

// RateLimitRetryConfig configures the retry wrapper. Zero values mean
// "use the package default".
type RateLimitRetryConfig struct {
	// Budget caps the total wait this bead may spend on rate-limit retries.
	// Zero uses RateLimitRetryDefaultBudget. Negative disables retries entirely.
	Budget time.Duration
	// PerWaitCap caps a single retry wait. Zero uses
	// RateLimitRetryDefaultPerWaitCap.
	PerWaitCap time.Duration
	// Sleep is the function the wrapper calls between attempts. Defaults to
	// a context-aware time.Sleep. Tests inject a fake to avoid real waits.
	Sleep func(ctx context.Context, d time.Duration) error
	// Now returns the current time for HTTP-date arithmetic. Defaults to
	// time.Now.
	Now func() time.Time
	// OnRetry, when non-nil, is invoked after each wait + before the retry
	// attempt fires. Used by integration to emit the rate-limit-retry bead
	// event and the routing-engine RecordRouteAttempt feedback.
	OnRetry func(ctx context.Context, info RateLimitRetryInfo)
}

// RateLimitRetryInfo describes one rate-limit retry event for telemetry hooks.
type RateLimitRetryInfo struct {
	Attempt    int
	Wait       time.Duration
	Source     string
	Result     *Result
	Elapsed    time.Duration
	OverBudget bool
}

// resolved returns a copy of cfg with zero fields filled in from defaults.
func (cfg RateLimitRetryConfig) resolved() RateLimitRetryConfig {
	out := cfg
	if out.Budget == 0 {
		out.Budget = RateLimitRetryDefaultBudget
	}
	if out.PerWaitCap == 0 {
		out.PerWaitCap = RateLimitRetryDefaultPerWaitCap
	}
	if out.Sleep == nil {
		out.Sleep = ctxSleep
	}
	if out.Now == nil {
		out.Now = time.Now
	}
	return out
}

func ctxSleep(ctx context.Context, d time.Duration) error {
	if d <= 0 {
		return nil
	}
	t := time.NewTimer(d)
	defer t.Stop()
	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-t.C:
		return nil
	}
}

// RunWithRateLimitRetry invokes attempt and, when its result is a rate-limit
// signal per IsRateLimitResult, waits per EvaluateRateLimitWait and retries
// until either attempt returns a non-rate-limit result or the per-bead budget
// is exhausted. Budget exhaustion mutates the final result's Error to
// RateLimitBudgetExhaustedReason and returns it without further retries.
//
// The wrapper does NOT change provider availability state — the provider
// stays in rotation per AC #2 of ddx-c6e3db02. Per AC #6, callers wire
// RecordRouteAttempt via OnRetry for transparency.
func RunWithRateLimitRetry(ctx context.Context, cfg RateLimitRetryConfig, attempt func(ctx context.Context) (*Result, error)) (*Result, error) {
	if cfg.Budget < 0 {
		// Negative budget disables the wrapper entirely (parity with
		// "feature off"). Useful for tests and operator opt-out.
		return attempt(ctx)
	}
	cfg = cfg.resolved()

	var (
		elapsed    time.Duration
		retryCount int
	)
	for {
		res, err := attempt(ctx)
		if err != nil || res == nil {
			return res, err
		}
		if !IsRateLimitResult(res) {
			return res, nil
		}

		retryCount++
		retryAfter := ExtractRetryAfterFromStderr(res.Stderr, cfg.Now())
		decision := EvaluateRateLimitWait(retryAfter, retryCount, elapsed, cfg.Budget, cfg.PerWaitCap)
		if !decision.ShouldRetry {
			// Budget exhausted: surface the canonical reason so the standard
			// execution_failed mapping fires (TD-031 §5).
			res.Error = RateLimitBudgetExhaustedReason
			if cfg.OnRetry != nil {
				cfg.OnRetry(ctx, RateLimitRetryInfo{
					Attempt:    retryCount,
					Source:     decision.Source,
					Result:     res,
					Elapsed:    elapsed,
					OverBudget: true,
				})
			}
			return res, nil
		}

		if cfg.OnRetry != nil {
			cfg.OnRetry(ctx, RateLimitRetryInfo{
				Attempt: retryCount,
				Wait:    decision.Wait,
				Source:  decision.Source,
				Result:  res,
				Elapsed: elapsed,
			})
		}

		if err := cfg.Sleep(ctx, decision.Wait); err != nil {
			return res, err
		}
		elapsed += decision.Wait
	}
}

// BuildRateLimitRouteAttempt constructs a fizeau.RouteAttempt that records a
// rate-limit retry on the routing-engine feedback channel. The Status is
// "rate_limited" so the engine has signal even though provider availability
// remains unchanged per RateLimitRetryContract.
func BuildRateLimitRouteAttempt(info RateLimitRetryInfo) agentlib.RouteAttempt {
	att := agentlib.RouteAttempt{
		Status:    "rate_limited",
		Reason:    info.Source,
		Duration:  info.Wait,
		Timestamp: time.Now().UTC(),
	}
	if info.Result != nil {
		att.Harness = info.Result.Harness
		att.Provider = info.Result.Provider
		att.Model = info.Result.Model
		att.Error = info.Result.Error
	}
	if info.OverBudget {
		att.Reason = RateLimitBudgetExhaustedReason
	}
	return att
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

const decomposerPromptSource = "bead-lifecycle-decompose"
const preClaimDecomposerPromptSource = "bead-lifecycle-preclaim-decompose"
const decomposerDefaultTimeout = 8 * time.Minute

// DecomposeResult is the outcome of a runDecomposer invocation.
type DecomposeResult struct {
	Failed   bool
	Reason   string
	ChildIDs []string
	CostUSD  float64
}

type decomposerChild struct {
	Title       string   `json:"title"`
	Description string   `json:"description"`
	Acceptance  string   `json:"acceptance"`
	Labels      []string `json:"labels,omitempty"`
}

type decomposerEventBody struct {
	ChildIDs []string `json:"child_ids"`
	CostUSD  float64  `json:"cost_usd,omitempty"`
}

// NewPreClaimDecompositionHook dispatches an orchestrator splitter for beads
// that readiness classifies as too_large without returning concrete children.
// It returns a lossless split proposal; the execute loop owns validation,
// child creation, dependency wiring, and fallback behavior.
func NewPreClaimDecompositionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) func(context.Context, string) (*PreClaimDecomposition, error) {
	return func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
		return runPreClaimDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
	}
}

func runPreClaimDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) (*PreClaimDecomposition, error) {
	tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
	defer cancel()

	b, err := store.Get(ctx, beadID)
	if err != nil {
		return nil, fmt.Errorf("decomposer: load bead: %w", err)
	}
	prompt, err := buildPreClaimDecomposerPrompt(store, b)
	if err != nil {
		return nil, err
	}
	runtime := AgentRunRuntime{
		Prompt:           prompt,
		PromptSource:     preClaimDecomposerPromptSource,
		ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	}
	result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
	if err != nil {
		if tctx.Err() != nil {
			return nil, tctx.Err()
		}
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, fmt.Sprintf("dispatch error: %s", err.Error())); fallbackErr == nil {
			return fallback, nil
		}
		return nil, fmt.Errorf("decomposer: dispatch: %w", err)
	}
	output := strings.TrimSpace(result.CondensedOutput)
	if output == "" {
		output = strings.TrimSpace(result.Output)
	}
	if output == "" {
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, "empty output"); fallbackErr == nil {
			return fallback, nil
		}
		return nil, fmt.Errorf("decomposer: empty output")
	}
	decomp, ok := parsePreClaimDecompositionOutput(output)
	if !ok {
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, "invalid output"); fallbackErr == nil {
			return fallback, nil
		}
		return nil, fmt.Errorf("decomposer: invalid output")
	}
	if err := validatePreClaimDecomposition(decomp); err != nil {
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, err.Error()); fallbackErr == nil {
			return fallback, nil
		}
		return nil, err
	}
	return decomp, nil
}

// NewDecomposePostLadderExhaustionHook creates a PostLadderExhaustionHook that
// dispatches runDecomposer for TooLarge failure class.
func NewDecomposePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
	return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		if failureClass != TooLarge {
			return &PostLadderExhaustionResult{Attempted: false}, nil
		}
		result := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
		if result.Failed {
			return &PostLadderExhaustionResult{
				Attempted: true,
				Succeeded: false,
				Path:      Decompose,
				CostUSD:   result.CostUSD,
			}, nil
		}
		return &PostLadderExhaustionResult{
			Attempted: true,
			Succeeded: true,
			Path:      Decompose,
			CostUSD:   result.CostUSD,
		}, nil
	}
}

// runDecomposer dispatches a smart+ powerClass agent to split the bead into child
// beads after the escalation ladder has been exhausted. On success, child beads
// are created with Parent=beadID, the parent's execution-eligible is set to
// false, and a "decompose-applied" event is emitted. On failure a
// DecomposeResult with Failed=true is returned.
func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
	tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
	defer cancel()

	b, err := store.Get(ctx, beadID)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "store_error"}
	}

	prompt, err := buildDecomposerPrompt(store, b)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "prompt_error"}
	}

	runtime := AgentRunRuntime{
		Prompt:           prompt,
		PromptSource:     decomposerPromptSource,
		ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	}

	result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
	if err != nil && result == nil {
		if tctx.Err() != nil {
			return DecomposeResult{Failed: true, Reason: "timeout"}
		}
		return DecomposeResult{Failed: true, Reason: "dispatch_error"}
	}

	output := strings.TrimSpace(result.CondensedOutput)
	if output == "" {
		output = strings.TrimSpace(result.Output)
	}
	if output == "" {
		return DecomposeResult{Failed: true, Reason: "empty_output", CostUSD: result.CostUSD}
	}

	children, ok := parseDecomposerOutput(output)
	if !ok {
		return DecomposeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
	}

	if len(children) < 1 || len(children) > 5 {
		return DecomposeResult{Failed: true, Reason: "invalid_count", CostUSD: result.CostUSD}
	}

	for _, child := range children {
		if strings.TrimSpace(child.Title) == "" ||
			strings.TrimSpace(child.Description) == "" ||
			strings.TrimSpace(child.Acceptance) == "" {
			return DecomposeResult{Failed: true, Reason: "malformed_child", CostUSD: result.CostUSD}
		}
	}

	childIDs := make([]string, 0, len(children))
	for _, child := range children {
		nb := &bead.Bead{
			Title:       strings.TrimSpace(child.Title),
			Description: strings.TrimSpace(child.Description),
			Acceptance:  strings.TrimSpace(child.Acceptance),
			Labels:      append([]string(nil), child.Labels...),
			Parent:      beadID,
		}
		if err := store.Create(context.Background(), nb); err != nil {
			return DecomposeResult{Failed: true, Reason: "create_error"}
		}
		childIDs = append(childIDs, nb.ID)
	}

	_ = store.Update(context.Background(), beadID, func(b *bead.Bead) {
		ensureBeadExtra(b)
		b.Extra[bead.ExtraExecutionElig] = false
	})

	body, _ := json.Marshal(decomposerEventBody{
		ChildIDs: childIDs,
		CostUSD:  result.CostUSD,
	})
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "decompose-applied",
		Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
		Body:      string(body),
		Actor:     "ddx work",
		Source:    "ddx work",
		CreatedAt: time.Now().UTC(),
	})

	return DecomposeResult{
		Failed:   false,
		ChildIDs: childIDs,
		CostUSD:  result.CostUSD,
	}
}

func buildDecomposerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
	type failureEntry struct {
		Summary string `json:"summary"`
		Body    string `json:"body,omitempty"`
	}
	type envelope struct {
		Title          string         `json:"title"`
		Description    string         `json:"description"`
		Acceptance     string         `json:"acceptance"`
		FailureHistory []failureEntry `json:"failure_history"`
	}

	env := envelope{
		Title:       strings.TrimSpace(b.Title),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
	}

	if events, err := store.Events(b.ID); err == nil {
		for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
			ev := events[i]
			switch ev.Kind {
			case "bead.result", "execute-bead", "per-bead-budget-exhausted":
			default:
				continue
			}
			env.FailureHistory = append(env.FailureHistory, failureEntry{
				Summary: strings.TrimSpace(ev.Summary),
				Body:    strings.TrimSpace(ev.Body),
			})
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", fmt.Errorf("decomposer: encode prompt: %w", err)
	}

	var sb strings.Builder
	sb.WriteString("MODE: decompose\n")
	sb.WriteString("You are splitting a bead that is too large into 2-5 independently executable child beads.\n")
	sb.WriteString("Each child must have a self-contained description, 3-6 numbered ACs with at least one named test function.\n")
	sb.WriteString("Return exactly one JSON array of child spec objects: [{\"title\":...,\"description\":...,\"acceptance\":...,\"labels\":[...]}]\n")
	sb.WriteString("Do not include prose or markdown; return only the JSON array.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

// parseDecomposerOutput extracts a JSON array of child specs from agent output.
func parseDecomposerOutput(output string) ([]decomposerChild, bool) {
	if c, ok := lastFencedBlock(output, "json"); ok {
		var children []decomposerChild
		if err := json.Unmarshal([]byte(strings.TrimSpace(c)), &children); err == nil {
			return children, true
		}
	}
	if c, ok := lastFencedBlock(output, ""); ok {
		trimmed := strings.TrimSpace(c)
		if strings.HasPrefix(trimmed, "[") {
			var children []decomposerChild
			if err := json.Unmarshal([]byte(trimmed), &children); err == nil {
				return children, true
			}
		}
	}
	// Scan for first '[' and balance brackets to find a raw JSON array.
	start := strings.Index(output, "[")
	if start == -1 {
		return nil, false
	}
	depth := 0
	for i := start; i < len(output); i++ {
		switch output[i] {
		case '[':
			depth++
		case ']':
			depth--
			if depth == 0 {
				var children []decomposerChild
				if err := json.Unmarshal([]byte(output[start:i+1]), &children); err == nil {
					return children, true
				}
				return nil, false
			}
		}
	}
	return nil, false
}

func buildPreClaimDecomposerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
	type failureEntry struct {
		Summary string `json:"summary"`
		Body    string `json:"body,omitempty"`
	}
	type envelope struct {
		Title          string         `json:"title"`
		Description    string         `json:"description"`
		Acceptance     string         `json:"acceptance"`
		Labels         []string       `json:"labels,omitempty"`
		Parent         string         `json:"parent,omitempty"`
		FailureHistory []failureEntry `json:"failure_history,omitempty"`
	}

	env := envelope{
		Title:       strings.TrimSpace(b.Title),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
		Labels:      append([]string(nil), b.Labels...),
		Parent:      strings.TrimSpace(b.Parent),
	}
	if events, err := store.Events(b.ID); err == nil {
		for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
			ev := events[i]
			switch ev.Kind {
			case "bead.result", "execute-bead", "intake.blocked", "pre_claim_intake.blocked", "no_changes_autonomous_retry":
			default:
				continue
			}
			env.FailureHistory = append(env.FailureHistory, failureEntry{
				Summary: strings.TrimSpace(ev.Summary),
				Body:    strings.TrimSpace(ev.Body),
			})
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", fmt.Errorf("decomposer: encode prompt: %w", err)
	}

	var sb strings.Builder
	sb.WriteString("MODE: preclaim-decompose\n")
	sb.WriteString("Split this too-large bead into 2-5 independently executable child beads.\n")
	sb.WriteString("Each child must be self-contained: include PROBLEM, ROOT CAUSE with file:line, PROPOSED FIX, NON-SCOPE, and numbered AC with named Test* symbols plus go test and lefthook gates.\n")
	sb.WriteString("Preserve every parent non-scope item, governing artifact reference, dependency ID, and verification requirement unless the AC map explicitly marks it non_scope.\n")
	sb.WriteString("Return exactly one JSON object: {\"children\":[{\"title\":...,\"description\":...,\"acceptance\":...,\"labels\":[...]}],\"ac_map\":[{\"parent_ac\":...,\"coverage\":...}],\"rationale\":...}.\n")
	sb.WriteString("Every parent acceptance criterion must appear in ac_map with non-empty coverage naming the child AC or non_scope/operator_required. Do not include prose or markdown.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func parsePreClaimDecompositionOutput(output string) (*PreClaimDecomposition, bool) {
	if c, ok := lastFencedBlock(output, "json"); ok {
		output = strings.TrimSpace(c)
	} else if c, ok := extractJSONCandidate(output); ok {
		output = strings.TrimSpace(c)
	}
	var decomp PreClaimDecomposition
	if err := json.Unmarshal([]byte(output), &decomp); err != nil {
		return nil, false
	}
	return &decomp, true
}

func validatePreClaimDecomposition(decomp *PreClaimDecomposition) error {
	if decomp == nil {
		return fmt.Errorf("decomposer: nil decomposition")
	}
	if len(decomp.Children) < 1 || len(decomp.Children) > 5 {
		return fmt.Errorf("decomposer: invalid child count %d", len(decomp.Children))
	}
	for i := range decomp.Children {
		child := &decomp.Children[i]
		child.Title = strings.TrimSpace(child.Title)
		child.Description = strings.TrimSpace(child.Description)
		child.Acceptance = strings.TrimSpace(child.Acceptance)
		if child.Title == "" || child.Description == "" || child.Acceptance == "" {
			return fmt.Errorf("decomposer: malformed child %d", i+1)
		}
	}
	for i := range decomp.ACMap {
		decomp.ACMap[i].ParentAC = strings.TrimSpace(decomp.ACMap[i].ParentAC)
		decomp.ACMap[i].Coverage = strings.TrimSpace(decomp.ACMap[i].Coverage)
	}
	decomp.Rationale = strings.TrimSpace(decomp.Rationale)
	return nil
}

func fallbackPreClaimDecomposition(b *bead.Bead, reason string) (*PreClaimDecomposition, error) {
	items := numberedAcceptanceItems(b.Acceptance)
	if len(items) == 0 {
		items = []string{
			"Implement the first bounded slice of the parent bead.",
			"Implement the remaining bounded slice of the parent bead.",
		}
	}
	childCount := 2
	if len(items) >= 12 {
		childCount = 5
	} else if len(items) >= 9 {
		childCount = 4
	} else if len(items) >= 5 {
		childCount = 3
	}
	if childCount > len(items) {
		childCount = len(items)
	}
	if childCount < 1 {
		return nil, fmt.Errorf("fallback decomposer: no child scopes")
	}

	chunks := chunkStrings(items, childCount)
	children := make([]PreClaimDecompositionChild, 0, len(chunks))
	acMap := make([]ACMapEntry, 0, len(items))
	parentSummary := clampForPrompt(strings.TrimSpace(b.Description), 2400)
	if parentSummary == "" {
		parentSummary = strings.TrimSpace(b.Title)
	}
	baseLabels := append([]string(nil), b.Labels...)
	baseLabels = appendUniqueLabel(baseLabels, "decomposed")
	for i, chunk := range chunks {
		if len(chunk) == 0 {
			continue
		}
		title := fallbackChildTitle(b.Title, i+1)
		description := fallbackChildDescription(b, parentSummary, chunk, i+1, len(chunks))
		acceptance := fallbackChildAcceptance(chunk, b.Acceptance)
		children = append(children, PreClaimDecompositionChild{
			Title:       title,
			Description: description,
			Acceptance:  acceptance,
			Labels:      append([]string(nil), baseLabels...),
		})
		for _, item := range chunk {
			acMap = append(acMap, ACMapEntry{
				ParentAC: item,
				Coverage: fmt.Sprintf("covered by child %d: %s", i+1, title),
			})
		}
	}
	if len(children) == 0 {
		return nil, fmt.Errorf("fallback decomposer: no child scopes")
	}
	return &PreClaimDecomposition{
		Children:  children,
		ACMap:     acMap,
		Rationale: "deterministic fallback split after agent decomposer returned " + strings.TrimSpace(reason),
	}, nil
}

func numberedAcceptanceItems(acceptance string) []string {
	lines := strings.Split(acceptance, "\n")
	items := make([]string, 0, len(lines))
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		dot := strings.Index(trimmed, ".")
		if dot <= 0 {
			continue
		}
		prefix := trimmed[:dot]
		if _, err := fmt.Sscanf(prefix, "%d", new(int)); err != nil {
			continue
		}
		item := strings.TrimSpace(trimmed[dot+1:])
		if item != "" {
			items = append(items, item)
		}
	}
	return items
}

func chunkStrings(items []string, chunks int) [][]string {
	if chunks <= 0 {
		return nil
	}
	out := make([][]string, 0, chunks)
	for i := 0; i < chunks; i++ {
		start := i * len(items) / chunks
		end := (i + 1) * len(items) / chunks
		out = append(out, items[start:end])
	}
	return out
}

func fallbackChildTitle(parentTitle string, n int) string {
	title := strings.TrimSpace(parentTitle)
	if len(title) > 72 {
		title = strings.TrimSpace(title[:72])
	}
	if title == "" {
		title = "decomposed bead"
	}
	return fmt.Sprintf("%s: part %d", title, n)
}

func fallbackChildDescription(parent *bead.Bead, parentSummary string, chunk []string, n, total int) string {
	var sb strings.Builder
	sb.WriteString("PROBLEM\n")
	sb.WriteString("Parent bead ")
	sb.WriteString(parent.ID)
	sb.WriteString(" is too broad for one execution pass. This child owns part ")
	sb.WriteString(fmt.Sprintf("%d of %d", n, total))
	sb.WriteString(" of that parent scope.\n\nROOT CAUSE\n")
	sb.WriteString(parentSummary)
	sb.WriteString("\n\nPROPOSED FIX\nImplement only this child acceptance slice:\n")
	for _, item := range chunk {
		sb.WriteString("- ")
		sb.WriteString(item)
		sb.WriteByte('\n')
	}
	sb.WriteString("\nNON-SCOPE\nDo not implement parent acceptance criteria assigned to sibling child beads. Preserve every parent non-scope constraint unless this child explicitly narrows it.")
	return sb.String()
}

func fallbackChildAcceptance(chunk []string, parentAcceptance string) string {
	var sb strings.Builder
	for i, item := range chunk {
		sb.WriteString(fmt.Sprintf("%d. %s\n", i+1, item))
	}
	next := len(chunk) + 1
	if !strings.Contains(parentAcceptance, "go test") {
		sb.WriteString(fmt.Sprintf("%d. cd cli && go test ./... passes.\n", next))
		next++
	}
	if !strings.Contains(parentAcceptance, "lefthook run pre-commit") {
		sb.WriteString(fmt.Sprintf("%d. lefthook run pre-commit passes.\n", next))
	}
	return strings.TrimSpace(sb.String())
}

func appendUniqueLabel(labels []string, label string) []string {
	for _, existing := range labels {
		if existing == label {
			return labels
		}
	}
	return append(labels, label)
}

func clampForPrompt(s string, max int) string {
	if max <= 0 || len(s) <= max {
		return s
	}
	return strings.TrimSpace(s[:max]) + "\n...[truncated]"
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

const reframerPromptSource = "bead-lifecycle-reframe"
const reframerDefaultTimeout = 5 * time.Minute

// ReframeResult is the outcome of a runReframer invocation.
type ReframeResult struct {
	Failed         bool
	Reason         string
	NewDescription string
	NewAcceptance  string
	CostUSD        float64
}

type reframerOutput struct {
	Description *string `json:"description"`
	Acceptance  *string `json:"acceptance"`
}

type reframerEventBody struct {
	CostUSD            float64 `json:"cost_usd,omitempty"`
	DescriptionChanged bool    `json:"description_changed"`
	AcceptanceChanged  bool    `json:"acceptance_changed"`
}

// NewReframePostLadderExhaustionHook creates a PostLadderExhaustionHook that
// dispatches runReframer for SpecGap and PersistentExecutionFailed failure
// classes. TooLarge is not handled here; it belongs to the Decompose path.
func NewReframePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
	return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		switch failureClass {
		case SpecGap, PersistentExecutionFailed:
		default:
			return &PostLadderExhaustionResult{Attempted: false}, nil
		}
		result := runReframer(ctx, store, runner, rcfg, projectRoot, beadID)
		if result.Failed {
			return &PostLadderExhaustionResult{
				Attempted: true,
				Succeeded: false,
				Path:      Reframe,
				CostUSD:   result.CostUSD,
			}, nil
		}
		return &PostLadderExhaustionResult{
			Attempted: true,
			Succeeded: true,
			Path:      Reframe,
			CostUSD:   result.CostUSD,
		}, nil
	}
}

// runReframer dispatches a smart+ powerClass agent to rewrite the bead's description
// and acceptance criteria after the escalation ladder has been exhausted.
// On success, the bead description/AC are updated, the
// consecutive_ladder_exhaustions counter is cleared, and a "reframe-applied"
// event is emitted. On failure a ReframeResult with Failed=true is returned.
func runReframer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) ReframeResult {
	tctx, cancel := context.WithTimeout(ctx, reframerDefaultTimeout)
	defer cancel()

	b, err := store.Get(ctx, beadID)
	if err != nil {
		return ReframeResult{Failed: true, Reason: "store_error"}
	}

	prompt, err := buildReframerPrompt(store, b)
	if err != nil {
		return ReframeResult{Failed: true, Reason: "prompt_error"}
	}

	runtime := AgentRunRuntime{
		Prompt:           prompt,
		WorkDir:          projectRoot,
		PromptSource:     reframerPromptSource,
		ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	}

	result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
	if err != nil && result == nil {
		if tctx.Err() != nil {
			return ReframeResult{Failed: true, Reason: "timeout"}
		}
		return ReframeResult{Failed: true, Reason: "dispatch_error"}
	}

	output := strings.TrimSpace(result.CondensedOutput)
	if output == "" {
		output = strings.TrimSpace(result.Output)
	}
	if output == "" {
		return ReframeResult{Failed: true, Reason: "empty_output", CostUSD: result.CostUSD}
	}

	candidate, ok := extractJSONCandidate(output)
	if !ok {
		return ReframeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
	}

	var parsed reframerOutput
	if err := json.Unmarshal([]byte(candidate), &parsed); err != nil {
		return ReframeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
	}
	if parsed.Description == nil && parsed.Acceptance == nil {
		return ReframeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
	}

	current, err := store.Get(context.Background(), beadID)
	if err != nil {
		return ReframeResult{Failed: true, Reason: "store_error"}
	}

	descChanged := parsed.Description != nil &&
		strings.TrimSpace(*parsed.Description) != strings.TrimSpace(current.Description)
	accChanged := parsed.Acceptance != nil &&
		strings.TrimSpace(*parsed.Acceptance) != strings.TrimSpace(current.Acceptance)

	if !descChanged && !accChanged {
		return ReframeResult{Failed: true, Reason: "noop_edits", CostUSD: result.CostUSD}
	}

	var changedFields []string
	var rewrite PreClaimIntakeRewrite
	if descChanged {
		changedFields = append(changedFields, "description")
		rewrite.Description = strings.TrimSpace(*parsed.Description)
	}
	if accChanged {
		changedFields = append(changedFields, "acceptance")
		rewrite.Acceptance = strings.TrimSpace(*parsed.Acceptance)
	}
	rewrite.ChangedFields = changedFields

	intake := PreClaimIntakeResult{
		Outcome: PreClaimIntakeActionableButRewritten,
		Detail:  "reframer rewrote bead after exhaustion",
		Rewrite: rewrite,
	}

	if err := applyPreClaimIntakeRewrite(store, beadID, "ddx work", intake, time.Now()); err != nil {
		return ReframeResult{Failed: true, Reason: "apply_error"}
	}

	_ = store.Update(context.Background(), beadID, func(b *bead.Bead) {
		ensureBeadExtra(b)
		delete(b.Extra, consecutiveLadderExhaustionsKey)
	})

	body, _ := json.Marshal(reframerEventBody{
		CostUSD:            result.CostUSD,
		DescriptionChanged: descChanged,
		AcceptanceChanged:  accChanged,
	})
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "reframe-applied",
		Summary:   strings.Join(changedFields, ","),
		Body:      string(body),
		Actor:     "ddx work",
		Source:    "ddx work",
		CreatedAt: time.Now().UTC(),
	})

	out := ReframeResult{
		Failed:  false,
		CostUSD: result.CostUSD,
	}
	if descChanged {
		out.NewDescription = rewrite.Description
	}
	if accChanged {
		out.NewAcceptance = rewrite.Acceptance
	}
	return out
}

func buildReframerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
	type failureEntry struct {
		Summary string `json:"summary"`
		Body    string `json:"body,omitempty"`
	}
	type envelope struct {
		Title          string         `json:"title"`
		Description    string         `json:"description"`
		Acceptance     string         `json:"acceptance"`
		FailureHistory []failureEntry `json:"failure_history"`
	}

	env := envelope{
		Title:       strings.TrimSpace(b.Title),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
	}

	if events, err := store.Events(b.ID); err == nil {
		for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
			ev := events[i]
			switch ev.Kind {
			case "bead.result", "execute-bead", "per-bead-budget-exhausted":
			default:
				continue
			}
			env.FailureHistory = append(env.FailureHistory, failureEntry{
				Summary: strings.TrimSpace(ev.Summary),
				Body:    strings.TrimSpace(ev.Body),
			})
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", fmt.Errorf("reframer: encode prompt: %w", err)
	}

	var sb strings.Builder
	sb.WriteString("MODE: reframe\n")
	sb.WriteString("You are rewriting a bead's description and acceptance criteria after repeated execution failures.\n")
	sb.WriteString("Your goal is to produce a clearer, more specific, implementation-ready bead.\n")
	sb.WriteString("Preservation rules: governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, dependency IDs (ddx-XXXXXXXX), and NON-SCOPE bullets must appear in any rewrite.\n")
	sb.WriteString("Return exactly one JSON object: {\"description\": string|null, \"acceptance\": string|null}\n")
	sb.WriteString("Use null to leave a field unchanged. At least one field must be non-null and meaningfully changed.\n")
	sb.WriteString("Do not include prose or markdown; return only the JSON object.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

package agent

import (
	"fmt"
	"strings"
)

// RepairPromptInput carries the evidence needed to ask an implementer to make
// one append-only repair commit in the still-live attempt worktree.
type RepairPromptInput struct {
	BeadID               string
	BaseRev              string
	FailedCandidateRev   string
	CycleIndex           int
	ReviewRationale      string
	PerAC                []ReviewAC
	Findings             []Finding
	VerificationCommands []string
}

// BuildRepairPrompt assembles the same-worktree repair prompt. The prompt is
// intentionally policy-heavy: repair passes may add one commit, but must never
// rewrite the existing implementation history.
func BuildRepairPrompt(input RepairPromptInput) string {
	var b strings.Builder
	fmt.Fprintf(&b, "Repair bead %s in the current attempt worktree.\n\n", input.BeadID)
	fmt.Fprintf(&b, "base_rev: %s\n", input.BaseRev)
	fmt.Fprintf(&b, "failed_candidate_rev: %s\n", input.FailedCandidateRev)
	fmt.Fprintf(&b, "repair_cycle_index: %d\n\n", input.CycleIndex)

	b.WriteString("Review findings:\n")
	if strings.TrimSpace(input.ReviewRationale) != "" {
		fmt.Fprintf(&b, "- %s\n", strings.TrimSpace(input.ReviewRationale))
	}
	for _, finding := range input.Findings {
		line := strings.TrimSpace(finding.Summary)
		if line == "" {
			continue
		}
		if loc := strings.TrimSpace(finding.Location); loc != "" {
			line = loc + ": " + line
		}
		if sev := strings.TrimSpace(finding.Severity); sev != "" {
			line = sev + ": " + line
		}
		fmt.Fprintf(&b, "- %s\n", line)
	}

	b.WriteString("\nPer-AC failures:\n")
	for _, ac := range input.PerAC {
		if strings.TrimSpace(ac.Evidence) == "" && strings.TrimSpace(ac.Grade) == "" {
			continue
		}
		fmt.Fprintf(&b, "- AC#%d %s %s %s\n", ac.Number, strings.TrimSpace(ac.Item), strings.TrimSpace(ac.Grade), strings.TrimSpace(ac.Evidence))
	}

	b.WriteString("\nVerification commands:\n")
	for _, cmd := range input.VerificationCommands {
		if strings.TrimSpace(cmd) == "" {
			continue
		}
		fmt.Fprintf(&b, "- %s\n", strings.TrimSpace(cmd))
	}

	b.WriteString("\nRules:\n")
	b.WriteString("- Work in the existing attempt worktree only.\n")
	b.WriteString("- Make exactly one append-only repair commit on top of the failed candidate.\n")
	b.WriteString("- Do not reset, amend, squash, rebase, cherry-pick over, or otherwise rewrite history.\n")
	b.WriteString("- Limit changes to the reviewer findings and the bead acceptance criteria.\n")
	return b.String()
}

package agent

// service_run.go provides Runner-free helpers that drive every operation via
// the agentlib.FizeauService service surface (CONTRACT-003). RunWithConfigViaService
// is the only run entry point; legacy RunViaService/RunViaServiceWith and the
// runFixtureHarnessViaRunner shim were retired in B22d-h.

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	agentlib "github.com/easel/fizeau"
)

// serviceRunFactory, when non-nil, overrides NewServiceFromWorkDir inside
// RunWithConfigViaService. CLI-level integration tests inject a stub to
// observe ServiceExecuteRequest fields without a real agent server.
var serviceRunFactory func(workDir string) (agentlib.FizeauService, error)

// fizeauHarness maps DDx internal harness names to the Fizeau wire contract.
// "agent" is DDx's internal name for the embedded native harness; Fizeau
// v0.10.12+ uses "fiz" as the native harness identity on its wire API.
func fizeauHarness(name string) string {
	if name == "agent" {
		return "fiz"
	}
	return name
}

// SetServiceRunFactory installs a service factory for RunWithConfigViaService.
// Pass nil to restore production behavior. Exported for cmd/ integration tests.
//
// Production reachability: invoked from init() with nil so the symbol is
// reachable from main() under deadcode RTA. Real overrides come from cmd/
// integration tests at test-setup time.
func SetServiceRunFactory(f func(workDir string) (agentlib.FizeauService, error)) {
	serviceRunFactory = f
}

func init() {
	// Reach SetServiceRunFactory from main() so it survives deadcode RTA.
	// The nil reset is a no-op: production never sets the factory.
	SetServiceRunFactory(nil)
}

// ResolveServiceFromWorkDir returns a service instance for the workdir,
// honoring any test override installed via SetServiceRunFactory.
func ResolveServiceFromWorkDir(workDir string) (agentlib.FizeauService, error) {
	return resolveService(workDir)
}

// resolveService returns a FizeauService for workDir, using the test-injected
// factory when set and the production NewServiceFromWorkDir otherwise. All
// internal callers (RunWithConfigViaService, ValidateForExecuteLoopViaService,
// etc.) must go through this helper so test stubs installed via
// SetServiceRunFactory are honored everywhere.
func resolveService(workDir string) (agentlib.FizeauService, error) {
	factory := serviceRunFactory
	if factory == nil {
		factory = NewServiceFromWorkDir
	}
	return factory(workDir)
}

// appendProviderTimeoutHint appends a configuration override hint to errMsg
// when it indicates a provider request timeout fired. Helps operators find
// the knob to adjust (AC4 of ddx-2c63bb95).
func appendProviderTimeoutHint(errMsg string, providerTimeout time.Duration) string {
	if errMsg == "" || !strings.Contains(errMsg, "provider request timeout") {
		return errMsg
	}
	return errMsg + fmt.Sprintf(
		"; request_timeout=%s exceeded — override via"+
			" agent.endpoints.<name>.request_timeout_seconds in .ddx/config.yaml"+
			" or pass --request-timeout DURATION to execute-bead/work",
		providerTimeout.Round(time.Second),
	)
}

// RunWithConfigViaService dispatches a single agent invocation through the
// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
// successor to the retired RunViaService/RunViaServiceWith entry points.
//
// The virtual and script harnesses route through a DDx-owned Runner path,
// not the upstream service. These are not "carve-outs pending migration" —
// they are different products from upstream's same-named stubs. DDx's
// virtual is a content-addressed record/replay dictionary keyed by
// PromptHash; upstream's is a unit-test stub where callers stuff
// virtual.response into Metadata. DDx's script reads a filesystem directive
// file; upstream does not model this at all.
func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	if ctx == nil {
		ctx = context.Background()
	}

	harness := rcfg.Passthrough().Harness

	effectivePerms := runtime.PermissionsOverride
	if effectivePerms == "" {
		effectivePerms = rcfg.Permissions()
	}
	if err := ValidateReadOnlyReviewerDispatch(harness, effectivePerms); err != nil {
		return nil, err
	}

	if harness == "virtual" || harness == "script" {
		sessionLogDir := runtime.SessionLogDirOverride
		if sessionLogDir == "" {
			sessionLogDir = rcfg.SessionLogDir()
		}
		cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
		r := NewRunner(cfg)
		r.WorkDir = workDir
		return r.runInternal(RunArgs{
			Context:       ctx,
			Harness:       rcfg.Harness(),
			Prompt:        runtime.Prompt,
			PromptFile:    runtime.PromptFile,
			PromptSource:  runtime.PromptSource,
			Correlation:   runtime.Correlation,
			Model:         rcfg.Model(),
			Provider:      rcfg.Provider(),
			Effort:        rcfg.Effort(),
			Timeout:       rcfg.Timeout(),
			WallClock:     rcfg.WallClock(),
			WorkDir:       runtime.WorkDir,
			Permissions:   rcfg.Permissions(),
			SessionLogDir: sessionLogDir,
			Env:           runtime.Env,
		})
	}

	svc, err := resolveService(workDir)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}
	return executeOnService(ctx, svc, workDir, rcfg, runtime)
}

// executeOnService dispatches against a pre-built svc using the durable
// knobs from rcfg and per-invocation plumbing from runtime, then records
// one session-index row. It is the inlined replacement for the retired
// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	if svc == nil {
		return nil, fmt.Errorf("agent: nil service")
	}
	if ctx == nil {
		ctx = context.Background()
	}

	promptText := runtime.Prompt
	if runtime.PromptFile != "" {
		data, err := readPromptFileBounded(runtime.PromptFile)
		if err != nil {
			return nil, fmt.Errorf("agent: read prompt file: %w", err)
		}
		promptText = string(data)
	}
	if promptText == "" {
		return nil, fmt.Errorf("agent: prompt is required")
	}

	wd := runtime.WorkDir
	if wd == "" {
		wd = workDir
	}
	if wd == "" {
		wd, _ = os.Getwd()
	}

	idle := rcfg.Timeout()
	if idle <= 0 {
		idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
	}
	wall := rcfg.WallClock()
	if wall <= 0 {
		wall = time.Duration(DefaultWallClockMS) * time.Millisecond
	}

	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}
	if sessionLogDir == "" {
		sessionLogDir = ResolveLogDir(workDir, "")
	}

	pt := rcfg.Passthrough()

	harness := runtime.HarnessOverride
	if harness == "" && !runtime.ClearRoutingPins {
		harness = pt.Harness
	}

	model := runtime.ModelOverride
	if model == "" && !runtime.ClearRoutingPins {
		model = pt.Model
	}

	provider := runtime.ProviderOverride
	if provider == "" && !runtime.ClearRoutingPins {
		provider = pt.Provider
	}
	if runtime.ClearRoutingPins && runtime.ProviderOverride == "" {
		provider = ""
	}

	profile := runtime.ProfileOverride
	if profile == "" && !runtime.ClearProfile {
		profile = rcfg.Profile()
	}

	permissions := runtime.PermissionsOverride
	if permissions == "" {
		permissions = rcfg.Permissions()
	}

	providerTimeout := ResolveProviderRequestTimeout(workDir, provider, model, rcfg.ProviderRequestTimeout())

	minPower := rcfg.MinPower()
	if runtime.MinPowerOverride > 0 {
		minPower = runtime.MinPowerOverride
	}
	if runtime.ClearMinPower {
		minPower = 0
	}
	maxPower := rcfg.MaxPower()
	if runtime.ClearMaxPower {
		maxPower = 0
	}
	if minPower > 0 && maxPower > 0 && minPower >= maxPower {
		return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
	}

	req := agentlib.ServiceExecuteRequest{
		Prompt:                promptText,
		Model:                 model,
		Policy:                profile,
		Provider:              provider,
		Harness:               fizeauHarness(harness),
		Reasoning:             agentlib.Reasoning(rcfg.Effort()),
		Permissions:           permissions,
		WorkDir:               wd,
		Timeout:               wall,
		IdleTimeout:           idle,
		ProviderTimeout:       providerTimeout,
		SessionLogDir:         sessionLogDir,
		Metadata:              metadataWithEnv(runtime.Correlation, runtime.Env),
		Role:                  runtime.Role,
		CorrelationID:         runtime.CorrelationID,
		MinPower:              minPower,
		MaxPower:              maxPower,
		EstimatedPromptTokens: firstPositiveInt(runtime.EstimatedPromptTokens, estimatePromptTokens(promptText)),
		RequiresTools:         runtime.RequiresTools,
	}
	seedRecentRouteAttemptsFromTracker(ctx, svc, workDir, time.Now().UTC())

	cancelCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	// When Harness is set and Model is empty, fizeau routes within the harness's
	// eligible models using Profile/MinPower as the routing constraint. This is the
	// well-formed request shape for profile-driven dispatch without an explicit model.
	// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
	// errors and a failed final event for post-dispatch errors.
	start := time.Now().UTC()
	events, err := svc.Execute(cancelCtx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	workPhase := strings.TrimSpace(runtime.WorkLogPhase)
	if workPhase == "" {
		workPhase = "do"
	}
	renderer := NewWorkLogRenderer(WorkLogRendererOptions{
		CurrentBeadID: runtime.Correlation["bead_id"],
		WorkPhase:     workPhase,
	})
	watchdog := &drainWatchdog{
		cancel:          cancel,
		idleTimeout:     idle,
		toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
	}
	final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer, watchdog)
	finishedAt := time.Now().UTC()
	elapsed := finishedAt.Sub(start)

	result := &Result{
		Harness:    fizeauHarness(harness),
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		if routing.Harness != "" {
			result.Harness = routing.Harness
		}
		if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
			result.PredictedPower = power
			result.PredictedSpeedTPS = speed
			result.PredictedCostUSDPer1kTokens = cost
			result.PredictedCostSource = source
		}
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e);
		// reviewer verdict extraction now parses this instead of raw stream
		// frames (ddx-7bc0c8d5).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int (nullable).
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.CacheReadTokens != nil {
				result.CachedTokens = *final.Usage.CacheReadTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		result.ExitCode = final.ExitCode
		result.Error = final.Error
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
			if final.RoutingActual.Harness != "" {
				result.Harness = final.RoutingActual.Harness
			}
			if final.RoutingActual.Power > 0 {
				result.ActualPower = final.RoutingActual.Power
			}
		}
		if final.SessionLogPath != "" {
			result.AgentSessionID = final.SessionLogPath
		}
	}
	result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
	normalizeServiceFinalExitCode(result)
	recordServiceRouteAttempt(ctx, svc, result, elapsed, finishedAt)
	entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
		Harness:     harness,
		Model:       model,
		Provider:    provider,
		Effort:      rcfg.Effort(),
		Correlation: runtime.Correlation,
	}, result, start, finishedAt)
	_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
	return result, nil
}

func estimatePromptTokens(prompt string) int {
	prompt = strings.TrimSpace(prompt)
	if prompt == "" {
		return 0
	}
	return (len(prompt) + 3) / 4
}

func firstPositiveInt(values ...int) int {
	for _, value := range values {
		if value > 0 {
			return value
		}
	}
	return 0
}

func seedRecentRouteAttemptsFromTracker(ctx context.Context, svc agentlib.FizeauService, projectRoot string, now time.Time) {
	if svc == nil || strings.TrimSpace(projectRoot) == "" {
		return
	}
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	beads, err := store.List("", "", nil)
	if err != nil {
		return
	}
	cutoff := now.Add(-ProviderUnavailableCooldown)
	seen := map[string]struct{}{}
	for _, b := range beads {
		for _, failed := range readFailedRoutes(b.Extra) {
			at, _ := time.Parse(time.RFC3339, strings.TrimSpace(failed.At))
			if at.IsZero() {
				at = now
			}
			if at.Before(cutoff) || at.After(now.Add(time.Minute)) || strings.TrimSpace(failed.Provider) == "" {
				continue
			}
			key := "\x00" + failed.Provider + "\x00" + failed.Model
			if _, ok := seen[key]; ok {
				continue
			}
			seen[key] = struct{}{}
			// Rebase replayed failures to `now` so they survive fizeau's
			// route-health TTL window. Historical tracker timestamps (minutes
			// to ~15 min old) sit outside fizeau's default 30s cooldown and
			// are dropped immediately by ActiveAttempts, leaving policy/default
			// Execute routes free to re-pick the same failed provider. The
			// tracker-side cutoff above (ProviderUnavailableCooldown) decides
			// which failures are still worth replaying; once they pass that
			// gate they are asserted active for fizeau's TTL counted from now.
			_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
				Provider:  failed.Provider,
				Model:     failed.Model,
				Status:    "failed",
				Reason:    FailureModeProviderConnectivity,
				Error:     FailureModeProviderConnectivity,
				Timestamp: now,
			})
		}
		events, err := store.Events(b.ID)
		if err != nil {
			continue
		}
		for _, ev := range events {
			if ev.Kind != "route-failure" || ev.CreatedAt.Before(cutoff) || ev.CreatedAt.After(now.Add(time.Minute)) {
				continue
			}
			var body map[string]any
			if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
				continue
			}
			if strings.TrimSpace(fmt.Sprint(body["outcome_reason"])) != FailureModeProviderConnectivity {
				continue
			}
			provider := strings.TrimSpace(fmt.Sprint(body["provider"]))
			if provider == "" || provider == "<nil>" {
				continue
			}
			harness := strings.TrimSpace(fmt.Sprint(body["harness"]))
			model := strings.TrimSpace(fmt.Sprint(body["model"]))
			key := harness + "\x00" + provider + "\x00" + model
			if _, ok := seen[key]; ok {
				continue
			}
			seen[key] = struct{}{}
			_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
				Harness:   harness,
				Provider:  provider,
				Model:     model,
				Status:    "failed",
				Reason:    FailureModeProviderConnectivity,
				Error:     strings.TrimSpace(fmt.Sprint(body["error"])),
				Timestamp: now,
			})
		}
	}
}

func recordServiceRouteAttempt(ctx context.Context, svc agentlib.FizeauService, result *Result, elapsed time.Duration, finishedAt time.Time) {
	if svc == nil || result == nil || strings.TrimSpace(result.Provider) == "" {
		return
	}
	status := "success"
	reason := "success"
	if result.ExitCode != 0 || strings.TrimSpace(result.Error) != "" {
		status = "failed"
		reason = "execution_failed"
		if strings.TrimSpace(result.Error) != "" {
			reason = "provider_error"
		}
	}
	_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
		Harness:   result.Harness,
		Provider:  result.Provider,
		Model:     result.Model,
		Status:    status,
		Reason:    reason,
		Error:     result.Error,
		Duration:  elapsed,
		Timestamp: finishedAt,
	})
}

func metadataWithEnv(metadata, env map[string]string) map[string]string {
	if len(metadata) == 0 && len(env) == 0 {
		return nil
	}
	out := make(map[string]string, len(metadata)+len(env))
	for k, v := range metadata {
		out[k] = v
	}
	for k, v := range env {
		out[k] = v
	}
	return out
}

func normalizeServiceFinalExitCode(result *Result) {
	if result == nil {
		return
	}
	if result.ExitCode == 0 && strings.TrimSpace(result.Error) != "" {
		result.ExitCode = 1
	}
}

// CapabilitiesViaService returns HarnessCapabilities for the named harness by
// querying the service's ListHarnesses and (best-effort) the harness registry.
// It is the production replacement for Runner.Capabilities.
func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	svc, err := resolveService(workDir)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return nil, fmt.Errorf("agent: list harnesses: %w", err)
	}
	var info *agentlib.HarnessInfo
	for i := range infos {
		if infos[i].Name == harnessName {
			info = &infos[i]
			break
		}
	}
	if info == nil {
		return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
	}

	// Pull binary and reasoning-level metadata from the local registry — the
	// service does not expose these directly today.
	registry := newHarnessRegistry()
	harness, _ := registry.Get(harnessName)

	caps := &HarnessCapabilities{
		Harness:             info.Name,
		Available:           info.Available,
		Binary:              harness.Binary,
		Path:                info.Path,
		Surface:             harness.Surface,
		CostClass:           info.CostClass,
		IsLocal:             info.CostClass == "local",
		ExactPinSupport:     info.ExactPinSupport,
		SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
		SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
	}
	if len(info.SupportedReasoning) > 0 {
		caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
	} else if len(harness.ReasoningLevels) > 0 {
		caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
	}

	if harness.DefaultModel != "" {
		caps.Model = harness.DefaultModel
		caps.Models = []string{harness.DefaultModel}
	}

	return caps, nil
}

// TestProviderConnectivityViaService runs a HealthCheck against the named
// harness and translates the result into a ProviderStatus. It is the
// production replacement for Runner.TestProviderConnectivity.
func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
	status := ProviderStatus{Reachable: false}
	if ctx == nil {
		ctx = context.Background()
	}
	if harnessName == "virtual" || harnessName == "agent" {
		status.Reachable = true
		status.CreditsOK = true
		return status
	}
	svc, err := resolveService(workDir)
	if err != nil {
		status.Error = err.Error()
		return status
	}
	if timeout > 0 {
		var cancel context.CancelFunc
		ctx, cancel = context.WithTimeout(ctx, timeout)
		defer cancel()
	}
	if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
		errStr := strings.ToLower(err.Error())
		status.Error = err.Error()
		if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
			strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
			status.CreditsOK = false
		}
		return status
	}
	status.Reachable = true
	status.CreditsOK = true
	return status
}

// ValidateForExecuteLoopViaService is the production replacement for
// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
// will pick at claim time). When harness is specified it confirms the harness
// exists in the service registry and (when model is set) attempts a
// ResolveRoute pre-flight.
func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider string) error {
	if harnessName == "" {
		return nil
	}
	if ctx == nil {
		ctx = context.Background()
	}
	svc, err := resolveService(workDir)
	if err != nil {
		return fmt.Errorf("agent: build service: %w", err)
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return fmt.Errorf("agent: list harnesses: %w", err)
	}
	found := false
	for _, info := range infos {
		if info.Name == harnessName {
			found = true
			if !info.Available {
				return fmt.Errorf("agent: harness %s not available", harnessName)
			}
			break
		}
	}
	if !found {
		return fmt.Errorf("agent: unknown harness: %s", harnessName)
	}

	// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
	// model is provided and provider is not set.
	if model != "" && provider == "" && harnessName == "agent" {
		if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
			Model:    model,
			Harness:  fizeauHarness(harnessName),
			Provider: provider,
		}); err != nil {
			return fmt.Errorf("agent: model %q is not routable: %w", model, err)
		}
	}
	return nil
}

// ValidateEffortForRunViaService rejects effort requests that no currently
// available harness can satisfy. `legacy agent run` passes effort through to the
// service rather than resolving a route locally, but the command still needs a
// fast failure for obviously impossible combinations so operators get a useful
// error instead of a silent success path.
func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
	if effort == "" {
		return nil
	}
	if ctx == nil {
		ctx = context.Background()
	}
	svc, err := resolveService(workDir)
	if err != nil {
		return fmt.Errorf("agent: build service: %w", err)
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return fmt.Errorf("agent: list harnesses: %w", err)
	}
	registry := newHarnessRegistry()
	for _, info := range infos {
		if !info.Available {
			continue
		}
		if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
			return nil
		}
	}
	if profile == "" {
		return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
	}
	return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
}

package agent

import "strings"

// IsLockContentionError reports whether errMsg names a transient lock-acquire
// failure that the dispatcher should retry. Patterns cover both git's index
// lock and ddx's own staging/tracker locks.
func IsLockContentionError(errMsg string) bool {
	lower := strings.ToLower(errMsg)
	return containsAny(lower,
		".git/index.lock",
		"unable to create '.git/index.lock'",
		"another git process seems to be running",
		"index.lock: file exists",
		"staging-tracker lock",
		"tracker lock held",
		"tracker is locked",
	)
}

// IsGitUpdateRefCompareAndSwapFailure reports whether errMsg is git's
// conditional update-ref race: the caller supplied an expected old SHA, but
// the ref had already advanced. This is coordination state, not a model
// implementation failure.
func IsGitUpdateRefCompareAndSwapFailure(errMsg string) bool {
	lower := strings.ToLower(errMsg)
	return strings.Contains(lower, "cannot lock ref") &&
		strings.Contains(lower, " is at ") &&
		strings.Contains(lower, " but expected ")
}

