281	// decodePreClaimIntakePayloadResult decodes a JSON payload into a PreClaimIntakeResult.
282	// It accepts both the legacy intake schema (classification field) and the canonical
283	// readiness schema (outcome field), converting both into the same decision model.
284	func decodePreClaimIntakePayloadResult(payload string) (PreClaimIntakeResult, error) {
285		var probe struct {
286			Classification string `json:"classification"`
287			Outcome        string `json:"outcome"`
288		}
289		if err := json.Unmarshal([]byte(payload), &probe); err != nil {
290			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
291		}
292		if probe.Outcome != "" {
293			return decodeCanonicalReadinessPayload(payload)
294		}
295		if probe.Classification != "" {
296			return decodeLegacyIntakePayload(payload)
297		}
298		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
299	}
300	
301	func decodeCanonicalReadinessPayload(payload string) (PreClaimIntakeResult, error) {
302		var out preClaimReadinessPromptResult
303		if err := json.Unmarshal([]byte(payload), &out); err != nil {
304			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
305		}
306		detail := strings.TrimSpace(out.Reason)
307		if detail == "" {
308			detail = strings.TrimSpace(out.Detail)
309		}
310		rewrite := PreClaimIntakeRewrite{
311			Description:   strings.TrimSpace(out.Rewrite.Description),
312			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
313			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
314		}
315		switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
316		case "actionable_atomic":
317			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail}, nil
318		case "actionable_but_rewritten":
319			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, Rewrite: rewrite}, nil
320		case "too_large_decomposed":
321			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: detail}, nil
322		case "ambiguous_needs_human":
323			return PreClaimIntakeResult{Outcome: PreClaimIntakeAmbiguousNeedsHuman, Detail: detail}, nil
324		case "readiness_error", "system_unready":
325			// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
326			return PreClaimIntakeResult{Outcome: PreClaimIntakeError, Detail: detail}, nil
327		case "":
328			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
329		default:
330			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, ambiguous_needs_human, readiness_error, system_unready", out.Outcome)
331		}
332	}
333	
334	func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
335		var out preClaimIntakePromptResult
336		if err := json.Unmarshal([]byte(payload), &out); err != nil {
337			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
338		}
339		switch strings.ToLower(strings.TrimSpace(out.Classification)) {
340		case "atomic":
341			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
342		case "rewritten":
343			return PreClaimIntakeResult{
344				Outcome: PreClaimIntakeActionableButRewritten,
345				Detail:  strings.TrimSpace(out.Reasoning),
346				Rewrite: PreClaimIntakeRewrite{
347					Description:   strings.TrimSpace(out.Rewrite.Description),
348					Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
349					ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
350				},
351			}, nil
352		case "decomposable":
353			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
354		case "ambiguous":
355			return PreClaimIntakeResult{Outcome: PreClaimIntakeAmbiguousNeedsHuman, Detail: strings.TrimSpace(out.Reasoning)}, nil
356		case "":
